-- CMS articles. Captured from production snapshot.
-- ============================================================

INSERT INTO "cms"."articles" ("id", "slug", "title", "description", "content", "content_format", "cover_image_url", "featured", "status", "attribution", "category_id", "published_at", "created_at", "updated_at", "deleted_at") VALUES
	('art_D5jvcc4GzBYGwpDwAj33W', 'understanding-linkedin-connection-types', 'Understanding LinkedIn Connection Types', 'We support multiple LinkedIn APIs allowing you to chose the best one for you.', '<p>When configuring LinkedIn for your application via <strong>Post for Me</strong>, you must choose between two distinct connection types: <strong>organization</strong> and <strong>personal</strong>. This setting determines the underlying LinkedIn API your app will use and dictates which types of pages your users are allowed to connect.</p><p><strong>Quickstart </strong>projects must always use <strong>organization</strong> as the connection type even if you are connecting a personal page.</p><p>Here is a breakdown of how to set the connection type, how the different types work, and which one you should choose based on your project configuration.</p><h2>Setting the Connection Type</h2><p>The connection type is a specific parameter passed during the initial OAuth setup.</p><h3><strong>How it works</strong></h3><p>When you make a <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">POST</code> request to the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">/v1/social-accounts/auth-url</code> endpoint to generate your authorization link, you specify the connection type inside the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">platform_data</code> object. If omitted, the API will default to the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">personal</code> connection type.</p><p><strong>Example Request:</strong></p><pre><code class="language-text">const response = await fetch(''https://api.postforme.dev/v1/social-accounts/auth-url'', {
  method: ''POST'',
  headers: {
    ''Content-Type'': ''application/json'',
    ''Authorization'': ''Bearer YOUR_API_KEY''
  },
  body: JSON.stringify({
    platform: ''linkedin'',
    platform_data: {
      linkedin: {
        connection_type: ''organization'' // Options are ''personal'' or ''organization''
      }
    }
  })
});

const { url } = await response.json();
</code></pre><h2>The Organization Connection Type</h2><p>The <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">organization</code> connection type utilizes the LinkedIn Community API.</p><h3><strong>How it works</strong></h3><p>This is the most comprehensive connection method. It allows your users to authenticate and connect <em>both</em> their <strong>personal</strong> profiles and any <strong>company</strong> pages they manage.</p><p>If you are using a <strong>Quickstart</strong> project with our provided credentials, you <strong>must</strong> always use the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">organization</code> option. If you are building a <strong>White Label</strong> project using your own credentials, you should only use this option if your native LinkedIn App is specifically configured for the Community API. Note that gaining access to the Community API requires your app to undergo an approval process and have a verified business on LinkedIn.</p><h2>The Personal Connection</h2><p>The <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">personal</code> connection type utilizes LinkedIn''s Sign In with OpenID Connect API.</p><h3><strong>How it works</strong></h3><p>This connection method is strictly limited. Users will only be able to connect their individual, personal LinkedIn pages. It does not support connecting or publishing to company pages.</p><p>This option is available for <strong>White Label</strong> projects that do not need company page access. Because it uses OpenID Connect, it does not require your LinkedIn App to go through a complex approval process or business verification, allowing you to get up and running much faster.</p><p></p>', 'html', NULL, false, 'published', NULL, 'cat_3idi40QLlh7LMIn3sM9mF', '2026-04-15 00:00:00+00', '2026-04-22 14:37:09.96524+00', '2026-04-22 14:37:09.96524+00', NULL),
	('art_wPSBO7Pj19dUPRXEu0Oh', 'posting-instagram-and-facebook-stories', 'Posting Instagram and Facebook Stories', 'Schedule and post stories through the API', '<p>When creating social media content, ephemeral formats like Stories offer a highly engaging way to connect with audiences. With <strong>Post for Me</strong>, you can specifically target the Stories placement for both <strong>Instagram</strong> and <strong>Facebook</strong> by utilizing platform configurations.</p><p>Here is a breakdown of how to control your story content placement and handle media assets.</p><h2>The Placement Configuration</h2><p>The <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">placement</code> parameter dictates exactly where your media will appear on the target platform''s ecosystem.</p><h3><strong>How it works:</strong></h3><p>When making a <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">POST</code> request to the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">/v1/social-posts</code> endpoint, you can include a <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">placement</code> string within the specific platform''s object (like <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">instagram</code> or <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">facebook</code>) inside your <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">platform_configurations</code> payload. </p><p>To publish a story, simply set the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">placement</code> value to <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">stories</code>. </p><h2>Handling Multiple Media Items</h2><p>Publishing multiple media assets to a Story placement behaves differently than standard timeline carousels.</p><h3><strong>How it works</strong></h3><p>If you include multiple media items in your <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">media</code> array while using the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">stories</code> placement, the system will automatically create individual posts for each distinct media item. </p><p><strong>Note: </strong>because these are processed as individual story uploads, each media item will count separately toward your overall post limits </p><p></p>', 'html', NULL, false, 'published', NULL, 'cat_3idi40QLlh7LMIn3sM9mF', '2026-03-20 00:00:00+00', '2026-04-22 14:37:09.990443+00', '2026-04-22 14:37:09.990443+00', NULL),
	('art_3PvW9cFXSuCxzQATOQ3vq', 'setting-up-multiple-environments', 'Setting Up Multiple Environments', 'Easily handle development, staging, and production environments.', '<p>When building a robust application, maintaining distinct environments for development, staging, and production is a best practice to ensure stable releases. With <strong>Post for Me</strong>, you can easily manage these different lifecycle stages by creating completely isolated projects for each of your environments.</p><p>Here is a breakdown of how to structure your projects to securely handle testing and production data.</p><h2>The Project-Based Architecture</h2><p>A <strong>project</strong> in Post for Me acts as a completely independent container for your API configurations, credentials, and user data.</p><h3><strong>How it works</strong></h3><p>Instead of trying to flag individual posts or accounts as "test" data within a single integration, you simply create a distinct project in your dashboard for each of your environments (e.g., "My App - Dev", "My App - Staging", "My App - Prod"). This guarantees total separation of concerns.</p><h2>Isolation of Configurations</h2><p>Because each project is strictly isolated, you must manage their specific configurations independently within your application''s environment variables.</p><h3><strong>How it works</strong></h3><p>Each project generates its own unique <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">API_KEY</code>. Furthermore, every project will have its own isolated database of connected social accounts, active webhooks, and global callback URLs. </p><p>This architecture ensures that a test account connected in your staging environment will never accidentally cross over, and test posts will never accidentally leak into your production environment. </p><h2>Mixing Project Types</h2><p>You are not locked into a single setup strategy across your entire development lifecycle; you can mix and match project types to optimize your workflow.</p><h3><strong>How it works</strong></h3><p>For example, you might create a <strong>Quickstart</strong> project for your development or staging environment. This allows your engineers to test features quickly using our system credentials without needing to wait for native platform app approvals. </p><p>Then, you can use a <strong>White Label</strong> project for your production environment. By doing this, your actual end-users will go through a fully branded OAuth flow using your own approved platform credentials, while your developers enjoy the frictionless testing of a Quickstart project locally.</p><p></p>', 'html', NULL, false, 'published', NULL, 'cat_3idi40QLlh7LMIn3sM9mF', '2026-03-12 20:57:54.939+00', '2026-04-22 14:37:10.003911+00', '2026-04-22 14:37:10.003911+00', NULL),
	('art_0LbN8b0wzrrkbXS2xRCje', 'linking-data-with-external-ids', 'Linking Data with External IDs', 'Easily link data by using your own unique identifiers through external ids', '<p>When building social media scheduling tools, mapping external API objects to your own internal database schema can be a headache. With <strong>Post for Me</strong>, you can utilize the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">external_id</code> parameter to effortlessly tie Social Accounts and Posts directly back to your internal users, simplifying your architecture and enhancing security.</p><p>Here is a breakdown of how to use external IDs to seamlessly integrate your data.</p><h2>Managing Social Accounts</h2><p>The <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">external_id</code> is a custom string you provide during the authentication flow that acts as your <strong>internal unique identifier </strong>for a user, team, or workspace.</p><h3><strong>How it works</strong> </h3><p>When generating an auth URL via the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">/v1/social-accounts/auth-url</code> endpoint, you can pass your custom <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">external_id</code> in the JSON payload. Once the user completes the connection, this ID is permanently attached to the newly created <strong>Social Account</strong> object.</p><p>When you query your connected accounts using the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">GET /v1/social-accounts</code> endpoint, you can filter the results directly by passing the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">?external_id=</code> query parameter. This makes it incredibly easy to load only the specific accounts belonging to the active user in your application without needing to maintain complex mapping tables.</p><h2>Tracking Social Posts</h2><p>Just like accounts, individual social media posts can also be tagged with an <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">external_id</code> during creation to link them to your internal records.</p><h3><strong>How it works</strong> </h3><p>When making a <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">POST</code> request to create a new post at <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">/v1/social-posts</code>, you simply include the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">external_id</code> string in your payload. This is highly useful for tying a specific post back to an internal campaign ID, project, or specific database row in your system.</p><p>You can instantly retrieve all posts associated with a specific campaign or internal user by filtering the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">GET /v1/social-posts</code> endpoint using the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">?external_id=</code> query parameter.</p><h2>Security and Preventing Account Hijacking</h2><p>Beyond basic data linking, the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">external_id</code> on Social Accounts acts as a strict ownership boundary, protecting your users'' connections from unauthorized access.</p><h3><strong>How it works</strong> </h3><p>If a user attempts to authenticate and connect a social profile that <strong>already exists </strong>in your system, the API checks the ownership. If the incoming connection attempt has a <strong><em>different</em></strong> <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">external_id</code> than the one currently saved on the existing account record, the system intercepts the request. </p><p>We will prevent the creation of the connection and throw an <strong>error</strong>. This crucial security measure prevents malicious actors from hijacking accounts connected under existing external IDs, ensuring that once a social profile is linked to a specific user in your database, it cannot be quietly taken over by another.</p><p></p>', 'html', NULL, false, 'published', NULL, 'cat_3idi40QLlh7LMIn3sM9mF', '2026-03-12 01:45:29.228+00', '2026-04-22 14:37:10.015262+00', '2026-04-22 14:37:10.015262+00', NULL),
	('art_twsWTwT4CMUvHqlHIj5uV', 'your-first-post', 'Your First Post', 'Step by step process to publish your first post!', '<p>Integrating social media publishing into your application shouldn''t take weeks. With <strong>Post for Me</strong>, you can execute your first cross-platform post in just three simple API calls. </p><p>Here is a breakdown of the core workflow to get your "Hello World" post live.</p><h2>Project Setup</h2><p>Before you can write any code to connect accounts, you must configure your project to allow specific networks.</p><h3><strong>How it works</strong> </h3><p>Navigate to your <strong>Post for Me</strong> project dashboard and explicitly enable the platforms you want to support (such as <strong>Facebook</strong>, <strong>X</strong>, or <strong>Instagram</strong>). If you skip this step, the authentication flow will fail because the API will not know which credentials to use.</p><h2>Step 1: Connect an Account</h2><p>To post on a user''s behalf, you must securely authenticate their social profile and obtain the necessary access tokens.</p><h3><strong>How it works</strong> </h3><p>Make a <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">POST</code> request to the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">/v1/social-accounts/auth-url</code> endpoint, passing the target <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">platform</code> in the body. The API will return a secure <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">url</code>.</p><p>You redirect your user to this URL. They will see an OAuth screen asking them to grant your application access to their account. Once approved, they are seamlessly redirected back to your application.</p><h2>Step 2: Retrieve the Account ID</h2><p>Every post requires a specific target destination, represented by a unique <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">social_account_id</code>.</p><h3><strong>How it works</strong> </h3><p>Once the user completes the connection flow, make a <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">GET</code> request to the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">/v1/social-accounts</code> endpoint. You can filter this request by passing query parameters like <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">?platform=facebook</code>.</p><p>The API returns an array of connected accounts. Extract the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">id</code> (e.g., <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">spc_12345</code>) from the returned data. You will use this ID to tell the API exactly where to send the content.</p><h2>Step 3: Publish the Post</h2><p>The final step is compiling your content and sending it to our servers for distribution.</p><h3><strong>How it works</strong></h3><p>Make a <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">POST</code> request to the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">/v1/social-posts</code> endpoint. Your JSON payload needs two primary fields at a minimum: </p><ul><li><p>A <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">caption</code> string for the text of the post. </p></li><li><p>A <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">social_accounts</code> array containing the IDs you retrieved in Step 2.</p></li></ul><p><strong>Note:</strong> If you are posting instantly, do not include a <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">scheduled_at</code> parameter. </p><p>The API returns a <strong>Social Post</strong> object with a <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">status</code> of <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">processing</code>. Within moments, the post will be distributed, and its status will change to <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">processed</code> as it goes live on the selected native social media platforms!</p><p></p>', 'html', NULL, false, 'published', NULL, 'cat_3idi40QLlh7LMIn3sM9mF', '2026-03-09 16:10:31.262+00', '2026-04-22 14:37:10.03944+00', '2026-04-22 14:37:10.03944+00', NULL),
	('art_CcsEMJd1El26H9jRTRde5', 'getting-started-with-the-threads-api', 'Threads API', 'Step-by-step guide for posting to Threads through the Post For Me API', '<h1>Threads Integration Guide</h1>
<p>This guide walks you through setting up a Threads (Meta) Developer App and integrating it into <strong>Post For Me</strong> so users can publish threads directly. Feel free to contact us at <a href="mailto:postforme@daymoon.dev">postforme@daymoon.dev</a> for any additional support!</p>
<hr />
<h2>1. Create a Facebook Developer Account</h2>
<ol>
<li><p>Go to <a href="https://developers.facebook.com">Facebook for Developers</a>.</p>
</li>
<li><p>Click <strong>Get Started</strong> and follow the prompts to register as a developer.</p>
<p>You need this to create a Threads application on the Meta platform.</p>
</li>
</ol>
<hr />
<h2>2. Create a Threads App</h2>
<ol>
<li>In the Facebook Developer Dashboard, click <strong>Create App</strong>.</li>
<li>Enter your app’s name and contact email.</li>
<li><strong>Under Use Case</strong>, choose <strong>Access the Threads API</strong>.</li>
<li>(Optional) Select a business portfolio.</li>
<li>Click <strong>Create App</strong>.</li>
</ol>
<hr />
<h2>3. Request Permissions for the Threads API</h2>
<ol>
<li>In the app sidebar, go to <strong>Use Cases</strong> → <strong>Access the Threads API</strong> → click <strong>Customize</strong>.</li>
<li>Enable these permissions:<ul>
<li><code>threads_content_publish</code></li>
<li><code>threads_manage_insights</code></li>
<li><code>threads_manage_replies</code></li>
</ul>
</li>
</ol>
<hr />
<h2>4. Configure Redirect &amp; Uninstall URLs</h2>
<ol>
<li><p>Still under <strong>Customize → Settings</strong>:</p>
<ul>
<li><p>Set <strong>Redirect Callback URL</strong> to:</p>
<p><a href="https://app.postforme.dev/callback/">https://app.postforme.dev/callback/</a>/threads/account</p>
<p>Replace <code>&lt;project_id&gt;</code> with your real project ID, or copy from <strong>Configure → Threads</strong> in Post For Me.</p>
</li>
<li><p>Set <strong>Uninstall Callback URL</strong> to:</p>
<p><a href="https://app.postforme.dev/callback/">https://app.postforme.dev/callback/</a>/threads/uninstall</p>
</li>
</ul>
</li>
<li><p>After entering each URL, make sure to click the dropdown suggestion so it registers correctly.</p>
</li>
</ol>
<hr />
<h2>5. Add Credentials to Post For Me</h2>
<ol>
<li>Copy your <strong>App ID</strong> and <strong>App Secret</strong> from the Facebook Developer Dashboard.</li>
<li>In <strong>Post For Me</strong>, go to: Configure -&gt; Threads</li>
<li>Paste the App ID and Secret into the corresponding fields.</li>
</ol>
<hr />
<h2>6. Add Threads Testers</h2>
<p>To allow sandbox testing while in Development Mode:</p>
<ol>
<li>In your Facebook Developer Dashboard, navigate to <strong>App Roles → Roles</strong>.</li>
<li>Click <strong>Add People</strong>, choose <strong>Threads Tester</strong>, and enter each Threads username to invite.</li>
<li>Invited users must:<ul>
<li>Log into their Threads account.</li>
<li>Go to <strong>Settings → Website Permissions → Invites</strong>.</li>
<li>Accept the tester invitation.</li>
</ul>
</li>
</ol>
<hr />
<h2>7. Finish App Setup</h2>
<ol>
<li>Return to <strong>Dashboard</strong> in your Developer Console.</li>
<li>Click <strong>Finish Customization</strong>.</li>
<li>Confirm by clicking <strong>Yes, I''m finished</strong>.</li>
</ol>
<hr />
<h2>8. Connect an Account and Test</h2>
<ol>
<li>In <strong>Post For Me</strong>: Project -&gt; Social Media Accounts -&gt; Connect an Account</li>
<li>Select <strong>Threads</strong>.</li>
<li>Follow the OAuth flow to connect your Threads account (must be an invited tester).</li>
</ol>
<p>You are now able to schedule and publish Threads posts via Post For Me.</p>
<hr />
<h2>9. Move to Production</h2>
<p>Once testing is complete:</p>
<ul>
<li>Apply for proper access via <strong>App Review</strong> in the Developer Dashboard to allow non-tester users to connect and post to Threads.</li>
</ul>
<hr />
<h2>Done!</h2>
<p>Your integration is ready. Users can connect their Threads profiles and begin posting directly from <strong>Post For Me</strong>!</p>
', 'html', NULL, false, 'published', NULL, 'cat_3idi40QLlh7LMIn3sM9mF', '2025-12-16 02:41:56.583+00', '2026-04-22 14:37:10.762531+00', '2026-04-22 14:37:10.762531+00', NULL),
	('art_xt3wGKPbkeZUZ03BJ6sw9', 'getting-started-with-the-linkedin-api', 'LinkedIn API', 'Step-by-step guide for posting to LinkedIn through the Post For Me API', '<h1>LinkedIn Integration Guide</h1>
<p>This guide provides step-by-step instructions for integrating LinkedIn with <strong>Post For Me</strong>, enabling users to schedule and publish posts to both personal accounts and business pages. Feel free to contact us at <a href="mailto:postforme@daymoon.dev">postforme@daymoon.dev</a> for any additional support!</p>
<hr />
<h2>1. Create a LinkedIn Developer Application</h2>
<ol>
<li>Navigate to the <a href="https://www.linkedin.com/developers/apps">LinkedIn Developer Dashboard</a> and click on <strong>Create App</strong>.</li>
<li>Fill in the required details:<ul>
<li><strong>App Name</strong>: Choose a name for your application.</li>
<li><strong>Company Name</strong>: Enter your company''s name.</li>
<li><strong>LinkedIn Page</strong>: Provide your company''s LinkedIn page URL.</li>
<li><strong>Privacy Policy URL</strong>: Link to your privacy policy.</li>
<li><strong>App Logo</strong>: Upload your application''s logo.</li>
</ul>
</li>
<li>Agree to the <a href="https://www.linkedin.com/legal/developer-agreement">LinkedIn Developer Terms of Use</a> and click <strong>Create App</strong>.</li>
</ol>
<hr />
<h2>2. Add Products to Your Application</h2>
<p>If you want to post on behalf of personal accounts:</p>
<ol>
<li>In your app settings, go to the <strong>Products</strong> tab.</li>
<li>Add the following products:<ul>
<li><strong>Share on LinkedIn</strong></li>
<li><strong>Sign In with LinkedIn using OpenID Connect</strong></li>
</ul>
</li>
<li>For each product, click <strong>Request Access</strong>, agree to the terms, and submit your request.</li>
</ol>
<p>If you want to post on behalf of personal accounts &amp; organizations:</p>
<ol>
<li>In your app settings, go to the <strong>Products</strong> tab.</li>
<li>Add the following products:<ul>
<li><strong>Community Management API</strong></li>
</ul>
</li>
<li>For each product, click <strong>Request Access</strong>, agree to the terms, and submit your request.</li>
</ol>
<blockquote>
<p><strong>Note</strong>: Access to the <strong>Community Management API</strong> is only available for legally registered entities (e.g., LLCs, Corporations, 501(c) organizations), not individual developers.</p>
</blockquote>
<hr />
<h2>3. Configure Redirect URIs</h2>
<ol>
<li><p>In your app''s <strong>Auth</strong> tab, under <strong>Authorized Redirect URLs</strong>, add:<code>https://app.postforme.dev/callback/&lt;project_id&gt;/linkedin/account</code></p>
<p>Replace <code>&lt;project_id&gt;</code> with your actual project ID, or copy the full url from the configure section</p>
</li>
</ol>
<hr />
<h2>4. Obtain API Credentials</h2>
<ol>
<li>In the <strong>Auth</strong> tab, copy your <strong>Client ID</strong> and <strong>Client Secret</strong>.</li>
</ol>
<hr />
<h2>5. Integrate Credentials into Post For Me</h2>
<ol>
<li>In the <strong>Post For Me</strong> dashboard, navigate to: Project -&gt; Configure -&gt; LinkedIn</li>
<li>Paste your <strong>Client ID</strong> and <strong>Client Secret</strong> into the respective fields.</li>
</ol>
<hr />
<h2>6. Connect LinkedIn Accounts</h2>
<ol>
<li>In <strong>Post For Me</strong>, go to: Project → Social Media Accounts → Connect an Account</li>
<li>Choose <strong>LinkedIn</strong>.</li>
<li>Complete the OAuth login flow to connect your account.</li>
</ol>
<blockquote>
<p><strong>Note</strong>: When connecting an account through the dashboard you will only have access to the personal account, to post on behalf of a business connect using the API<a href="https://api.postforme.dev/docs#tag/social-accounts/post/v1/social-accounts/auth-url"></a>.</p>
</blockquote>
<hr />
<h2>7. Application Review (For Community Management API)</h2>
<p>If you requested access to the <strong>Community Management API</strong>:</p>
<ol>
<li>Fill out the access request form with details about your organization and your app’s use case.</li>
<li>Submit it for LinkedIn''s review.</li>
<li>Wait for approval, which may take several days.</li>
</ol>
<hr />
<h2>Done!</h2>
<p>Your LinkedIn integration is complete. You can now schedule and publish posts to personal accounts and business pages through <strong>Post For Me</strong>.</p>
<hr />
<p>If you need assistance or more info on specific features, just ask!</p>
', 'html', NULL, false, 'published', NULL, 'cat_3idi40QLlh7LMIn3sM9mF', '2025-12-16 02:18:30.758+00', '2026-04-22 14:37:10.772711+00', '2026-04-22 14:37:10.772711+00', NULL),
	('art_fR6ETB3xNYE2hhW4Mo8Uj', 'posting-reels-and-stories', 'Posting Reels and Stories', 'Along with your timeline post to reels and stories through the API!', '<p>When creating a post through <strong>Post for Me</strong>, you are not limited to standard timeline updates. You can specifically target short-form video and ephemeral content formats, such as <strong>Reels</strong> and <strong>Stories</strong>, by utilizing platform or account configurations.</p><p>Here is a breakdown of how to control your content placement across different social networks.</p><h2>The Placement Configuration</h2><p>The <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">placement</code> parameter dictates exactly where your media will appear on the target platform''s ecosystem.</p><h3><strong>How it works</strong> </h3><p>When making a <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">POST</code> request to the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">/v1/social-posts</code> endpoint to create a post, you can include a <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">placement</code> string within the specific platform''s object (like <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">instagram</code>, <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">facebook</code>, or <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">threads</code>) inside your <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">platform_configurations</code> payload. </p><p>For both <strong>Instagram</strong> and <strong>Facebook</strong>, you can set the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">placement</code> value to <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">reels</code>, <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">stories</code>, or <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">timeline</code>. For <strong>Threads</strong>, the supported placements are <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">reels</code> and <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">timeline</code>.</p><h2>Instagram Reels Specifics</h2><p>When targeting Instagram Reels, you have additional control over how your videos are distributed and tested on the platform.</p><h3><strong>How it works</strong></h3><p>Alongside the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">placement</code> parameter, you can utilize specific Instagram configuration options to fine-tune the video''s behavior within the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">InstagramConfigurationDto</code>.</p><p><strong>The Feed Option:</strong> By default, Instagram Reels are shared to the main user feed. If you want your video post to only be shown in the Reels tab, you can pass the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">share_to_feed</code> boolean set to <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">false</code>.</p><p><strong>Trial Reels:</strong> You can also experiment with your content by passing the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">trial_reel_type</code> parameter. Setting this to <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">manual</code> means the trial reel can be manually graduated to the main grid in the native app, while setting it to <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">performance</code> will automatically graduate the reel if it performs well with your audience. <strong>Note: </strong>your account must have at least 1,000 followers to use trial reels</p><h2>Platform vs. Account Overrides</h2><p>You can choose to apply placement rules broadly across an entire network or restrict them to a single specific account.</p><h3><strong>How it works</strong></h3><p>If you want every Instagram account included in your post to publish a Story, you simply pass <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">placement: "stories"</code> inside the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">platform_configurations.instagram</code> object.</p><p>However, if a user selects multiple accounts but only wants one specific Facebook Page to post a Reel, you can use the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">account_configurations</code> array. By passing the specific <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">social_account_id</code> along with the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">placement</code> parameter there, you ensure the Reel is only published to that exact account, while the others default to their standard timeline presentation.</p>', 'html', NULL, false, 'published', NULL, 'cat_3idi40QLlh7LMIn3sM9mF', '2026-03-05 22:54:16.907+00', '2026-04-22 14:37:10.048841+00', '2026-04-22 14:37:10.048841+00', NULL),
	('art_IhYPqAxn9SBZIrhEPLx0O', 'creating-carousels-and-multi-media-posts', 'Creating Carousels and Multi-Media Posts', 'Post carousels simply by passing multiple media in a post', '<p>Your users will often want to share more than just a single image or video. <strong>Post for Me</strong> makes publishing carousels and multi-image posts incredibly straightforward across all supported platforms.</p><p>Here is a breakdown of how to seamlessly handle multiple media assets in a single post request.</p><h2>The Core Concept</h2><p>A <strong>carousel</strong> is a single social media post that contains multiple media assets, allowing users to swipe or click through a gallery of content.</p><h3><strong>How it works</strong> </h3><p>To publish a carousel, you do not need to use a special endpoint or distinct parameter. You simply pass multiple media objects into the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">media</code> array when making a <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">POST</code> request to the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">/v1/social-posts</code> endpoint. </p><ul><li><p>Provide a valid <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">url</code> for each asset within the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">media</code> array.</p></li><li><p>The API will automatically package these assets into the native carousel format for each targeted platform.</p></li></ul><h3><strong>The User Experience</strong></h3><p>The end-user will see a native multi-image or multi-video post on their timeline. They can swipe or click through the content exactly as if it were posted directly from the platform''s native app.</p><h2>Platform and Account Overrides</h2><p>You maintain full flexibility over your media, even when targeting multiple networks simultaneously.</p><h3><strong>How it works</strong></h3><p>If you want to post a multi-image carousel to <strong>Instagram</strong> but only a single image to <strong>Facebook</strong>, you can utilize the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">platform_configurations</code> or <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">account_configurations</code> objects.</p><ul><li><p>Simply pass a new <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">media</code> array containing your specific objects inside the respective platform''s configuration payload.</p></li><li><p>This override will replace the base post''s media entirely for that specific network or account, ensuring the most specific content is used.</p></li></ul><h3><strong>Requirements</strong></h3><p> While the Post for Me API accepts multiple media items effortlessly, it is important to remember that each social network enforces its own native limitations. If a platform (such as <strong>X</strong>) does not natively support the number of media items you have provided in your array, the post attempt for that specific network will fail.</p><p></p>', 'html', NULL, false, 'published', NULL, 'cat_3idi40QLlh7LMIn3sM9mF', '2026-03-04 16:56:30.431+00', '2026-04-22 14:37:10.058722+00', '2026-04-22 14:37:10.058722+00', NULL),
	('art_H8nhqCPPBTmeLF1vvNBfA', 'working-with-tiktok-drafts', 'Working with TikTok Drafts', 'Use TikTok drafts to get benefits of native posting and API scheduling.', '<p>When building social media scheduling tools, your users may want to leverage TikTok''s native editing tools, like trending audio or specific filters, before their video goes live. <strong>Post for Me</strong> supports this hybrid workflow by allowing you to push content directly into a user''s TikTok account as a draft.</p><p>Here is a breakdown of how to utilize TikTok drafts and how they differ from system-level drafts.</p><h2>The TikTok Draft Configuration</h2><p>The <strong>TikTok Draft</strong> feature allows you to upload media to the platform without immediately publishing it to the public feed.</p><h3><strong>How it works</strong> </h3><p>When creating a post, you pass the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">"is_draft": true</code> flag inside the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">tiktok</code> object within your <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">platform_configurations</code> payload. The API will process the video and send it to TikTok.</p><h3><strong>The User Experience</strong></h3><p>The end-user will receive a notification directly within their TikTok mobile app indicating a new draft is ready. They can then open the app, apply native TikTok effects, edit the caption, and manually hit publish when they are ready. This enables a seamless hand-off between your scheduling platform and native app posting.</p><h2>Platform Drafts vs. System Drafts</h2><p>It is critical to understand the distinction between sending a draft to <strong>TikTok</strong> and saving a draft within the <strong>Post for Me</strong> system.</p><h3><strong>How it works</strong> </h3><p>These are controlled by two entirely different parameters in your API request:</p><ul><li><p><strong>TikTok Configuration (</strong><code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">is_draft</code><strong>)</strong>: When set to <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">true</code> under <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">platform_configurations.tiktok</code>, the Post for Me system <strong>will process</strong> the post. The media is sent to TikTok''s servers, and the post status becomes <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">processed</code>, even though it is unpublished on the TikTok app.</p></li><li><p><strong>Parent Post Object (</strong><code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">isDraft</code><strong>)</strong>: When set to <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">true</code> at the root level of your post payload, the Post for Me system <strong>will not process</strong> the post. The post remains safely stored in your database as a draft and is never sent to TikTok (or any other connected platform).</p></li></ul><p><strong>Note:</strong> If you are using the TikTok Business connection, the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">is_draft</code> functionality behaves the same way, allowing professional users to stage their content natively.</p><p></p>', 'html', NULL, false, 'published', NULL, 'cat_3idi40QLlh7LMIn3sM9mF', '2026-03-03 23:27:40.706+00', '2026-04-22 14:37:10.071064+00', '2026-04-22 14:37:10.071064+00', NULL),
	('art_WKjbr4xqZSViFPQr0umyv', 'scheduling-and-managing-the-post-lifecycle', 'Scheduling and Managing the Post Lifecycle', 'Control when a post is published with our scheduling and draft features', '<p>With <strong>Post for Me</strong>, you can seamlessly manage the entire lifecycle of your social media content, from initial drafts to future scheduled campaigns.</p><p>Here is a breakdown of how to schedule posts, understand their lifecycle, and manage updates.</p><h2>Drafts vs. Scheduled Posts</h2><p>When creating a post, you have complete control over when it goes live.</p><h3><strong>How it works</strong></h3><p>You dictate the publishing timeline using two specific payload properties when creating a post:</p><ul><li><p><strong>Drafts:</strong> To save a work-in-progress, pass the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">isDraft</code> boolean flag as <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">true</code>. This tells the system that the post is not ready and should not be processed.</p></li><li><p><strong>Scheduled:</strong> To queue a post for a future date, pass a valid date-time string in the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">scheduled_at</code> field. </p></li><li><p><strong>Instant:</strong> If you set <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">scheduled_at</code> to <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">null</code> or omit it entirely (and <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">isDraft</code> is <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">false</code>), the post will be published instantly.</p></li></ul><h2>The Post Statuses</h2><p>As a post moves through our system, its <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">status</code> field automatically updates to reflect its current state. </p><p><strong>The Lifecycle:</strong> A post will transition through the following tracking statuses:</p><ol><li><p><code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">draft</code>: The post is safely stored but will not be published.</p></li><li><p><code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">scheduled</code>: The post is queued and waiting for its <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">scheduled_at</code> time to arrive.</p></li><li><p><code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">processing</code>: The time has arrived, and the post is actively being handed off to the targeted social platforms.</p></li><li><p><code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">processed</code>: The API has finished its publishing attempt across all targeted accounts.</p></li></ol><h2>Updating and Deleting Posts</h2><p>Content plans change, and the API allows you to modify or cancel posts before they go live.</p><h3><strong>How it works</strong></h3><p>You can modify an existing post''s caption, media, or timing by making a <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">PUT</code> request to the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">/v1/social-posts/{id}</code> endpoint. If you need to cancel it entirely, you can make a <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">DELETE</code> request to the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">/v1/social-posts/{id}</code> endpoint.</p><p><strong>Requirement:</strong> It’s important to note that you can <strong>only</strong> update or delete a post if its current status is <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">draft</code> or <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">scheduled</code>. Once a post transitions to <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">processing</code> or is fully <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">processed</code>, it can no longer be altered or deleted.</p><p></p>', 'html', NULL, false, 'published', NULL, 'cat_3idi40QLlh7LMIn3sM9mF', '2026-02-27 15:35:26.9+00', '2026-04-22 14:37:10.080767+00', '2026-04-22 14:37:10.080767+00', NULL),
	('art_CuCiDindRwUdMTaiW8pio', 'intercepting-the-oauth-flow', 'Intercepting the OAuth Flow', 'Fully control the OAuth flow with White Label projects.', '<p>When building a <strong>White Label</strong> project with <strong>Post for Me</strong>, you may want to intercept the OAuth authentication process so users hit your application before being sent to our servers. By using the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">redirect_url_override</code> parameter, you can gain complete control over the authorization flow and handle account connections exactly how your architecture requires.</p><p>Here is a breakdown of how to use redirect overrides and the two paths you can take to complete the connection.</p><h2>The Redirect URI Override</h2><p>The Redirect URI Override is a parameter passed when generating an authentication URL that replaces the default Post for Me redirect URI.</p><h3><strong>How it works</strong></h3><p>When making a <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">POST</code> request to the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">/v1/social-accounts/auth-url</code> endpoint, you pass your custom URL as the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">redirect_url_override</code>. After the user authorizes your app on the social platform, they are redirected to this custom URL instead of Post for Me''s servers.</p><h3><strong>Requirements</strong></h3><p>Because you are modifying the OAuth flow, this custom domain must be explicitly listed in the <strong>authorized redirect domains </strong>(or callback URLs) within the native developer portal of the specific social platform (e.g., your Meta App dashboard or Google Cloud Console).</p><p><strong>Note:</strong> This override feature is exclusive to projects using your <strong>own credentials </strong>and will not work if you are using our system credentials (Quickstart).</p><h2>Manual Account Creation</h2><p>Manual Account Creation is designed for developers who want to manage the OAuth token exchange themselves.</p><h3><strong>How it works</strong></h3><p>Once the social platform redirects the user to your custom URI, your server extracts the authorization code from the URL parameters. You then independently exchange this code for an access and refresh token directly with the social network.</p><h3><strong>The Workflow</strong></h3><p>After successfully retrieving the tokens, you make a <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">POST</code> request to the Post for Me <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">/v1/social-accounts</code> endpoint. You pass the newly generated tokens and user details to formally create the connection in our system, allowing you to handle the connection entirely <strong>server-side</strong>.</p><h2>Forwarded Account Connection</h2><p><strong>Forwarded Account Connection </strong>allows you to intercept the user journey for your own tracking or onboarding steps while still letting Post for Me handle the complex token exchange.</p><h3><strong>How it works</strong></h3><p>After the user hits your custom redirect URI, your application performs its necessary internal tasks. Then, you simply forward the entire request (including the authorization code parameters) to the standard Post for Me redirect URI.</p><h3>The Workflow</h3><p>We will process the forwarded request, seamlessly handle the token exchange, securely store the credentials, and finally redirect the user back to your global <strong>Project Callback URL</strong> upon completion. </p><p></p>', 'html', NULL, false, 'published', NULL, 'cat_3idi40QLlh7LMIn3sM9mF', '2026-02-24 15:06:30.014+00', '2026-04-22 14:37:10.096377+00', '2026-04-22 14:37:10.096377+00', NULL),
	('art_nM0i1j9o34OdHokBBby', 'posting-large-video-files', 'Posting Large Video Files', 'Post large video files quickly through the API.', '<p>When publishing content through <strong>Post for Me</strong>, our system generally processes media to ensure it is optimized for the destination networks. However, when your application needs to handle very large video files, you may want to prioritize speed over automatic optimization.</p><p>Here is a breakdown of how to handle large files using the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">skip_processing</code> flag.</p><h2>The Skip Processing Flag</h2><p>The <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">skip_processing</code><strong> flag</strong> is a media-level parameter designed to bypass our internal compression engines.</p><h3><strong>How it works</strong> </h3><p>When creating a post, you can pass the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">"skip_processing"</code> flag along with your media payload. This instructs the API to take your video file exactly as it is and pass it directly to the social platforms without altering or compressing it in any way.</p><h3><strong>The Benefit:</strong> </h3><p>By eliminating the transcoding and compression steps on our servers, you will significantly speed up the publishing process for larger files.</p><h2>Risks and Platform Constraints</h2><p>While bypassing processing increases speed, it places the responsibility of media formatting entirely on your application.</p><h3><strong>The Risk</strong></h3><p>Sending unaltered files may increase your post failure rate. If your raw media does not natively match the specific requirements (such as codec, bitrate, or aspect ratio) of the target platform, the platform will reject the upload.</p><h3><strong>Platform Limits</strong></h3><p>Be highly aware of specific network constraints. Certain platforms, such as <strong>Bluesky</strong> and <strong>X (Twitter)</strong>, have strict duration limits. If you attempt to post large video files that exceed these duration caps, those specific post results will fail.</p>', 'html', NULL, false, 'published', NULL, 'cat_3idi40QLlh7LMIn3sM9mF', '2026-02-20 20:26:29.872+00', '2026-04-22 14:37:10.108915+00', '2026-04-22 14:37:10.108915+00', NULL),
	('art_94Ets5uSwsdTbwvB1dT', 'pagination-account-feeds', 'Pagination & Account Feeds', 'Navigate through an account feed using pagination.', '<p>When retrieving the social history for a connected account, the amount of data can be extensive. To manage this efficiently and ensure fast response times, the <strong>Social Account Feed</strong> endpoint utilizes cursor-based pagination to retrieve posts in manageable chunks.</p><p>Here is a breakdown of how to control your batch sizes and navigate through the user''s history.</p><h2>Controlling Result Size</h2><p>You can control the number of items returned in a single request by utilizing the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">limit</code> parameter.</p><h3><strong>The Parameter</strong></h3><p>By default, the endpoint returns a set number of posts (usually 50). You can adjust this by passing <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">?limit=X</code> in your query string.</p><h3><strong>Platform Limits:</strong> </h3><p>It is important to note that every social platform (e.g., Instagram, YouTube) enforces its own maximum page size.</p><ul><li><p><strong>The Logic:</strong> If the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">limit</code> you provide is higher than what the specific platform allows, we will automatically default to the <strong>maximum limit allowed by that platform</strong>.</p></li><li><p><strong>The Result:</strong> You may receive fewer items than requested, but you will never receive an error for requesting too many.</p></li></ul><h2>Navigating with Cursors</h2><p>To retrieve the next set of results, you must use the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">cursor</code> parameter. Unlike internal endpoints that may use numbered offsets, external social feeds rely on opaque cursor strings to track position in the timeline.</p><h3><strong>How it works</strong></h3><ol><li><p><strong>Check the Meta:</strong> Every response includes a <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">meta</code> object. Check the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">has_more</code> boolean to see if additional posts exist.</p></li><li><p><strong>Get the Cursor:</strong> If more data is available, extract the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">cursor</code> string from the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">meta</code> object.</p></li><li><p><strong>The Next Request:</strong> Pass this string as the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">cursor</code> query parameter in your subsequent request to fetch the next page.</p></li></ol><h3><strong>The Helper</strong></h3><p>To make this even easier, the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">meta</code> object also includes a pre-built <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">next</code> URL, which already contains the correct cursor and limit settings for the following page.</p><p></p>', 'html', NULL, false, 'published', NULL, 'cat_3idi40QLlh7LMIn3sM9mF', '2026-02-18 15:04:09.457+00', '2026-04-22 14:37:10.11961+00', '2026-04-22 14:37:10.11961+00', NULL),
	('art_NQcUSZnB13oVGIYdLhrO', 'handling-account-disconnections', 'Handling Account Disconnections', 'Disconnect and reconnect accounts without worry of data loss.', '<p>When managing user lifecycles in your application, there are times when a user may want to remove a specific social account or revoke access entirely. <strong>Post for Me</strong> handles disconnections in a way that prioritizes security while preserving historical data for future re-connections.</p><p>Here is a breakdown of how the disconnection process works and what happens to the data.</p><h2>The Disconnect Process</h2><p>Disconnecting an account is a specific action that revokes our ability to post on the user''s behalf without destroying the analytics history associated with that account.</p><h3><strong>How it works</strong></h3><p>You make a <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">POST</code> request to the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">/v1/social-accounts/{id}/disconnect</code> endpoint. Upon success, the account''s <strong>status</strong> is immediately updated to <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">disconnected</code>.</p><h3><strong>Security</strong></h3><p>Crucially, this process permanently removes the <strong>access tokens</strong> and <strong>refresh tokens</strong> associated with the account. Once disconnected, the API can no longer query feeds or publish posts for that specific account.</p><h2>Data Preservation</h2><p>Unlike a hard delete, disconnecting an account does not wipe the record from our database.</p><h3><strong>The Logic</strong></h3><p>We maintain the account record in a <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">disconnected</code> state. This ensures that if the user decides to reconnect the account later, their previous configuration, internal IDs, and historical data are preserved.</p><h3><strong>The User Experience</strong></h3><p>If a user disconnects their LinkedIn page but reconnects it a month later, your application can resume service immediately without needing to re-map the external IDs or lose track of previous posts.</p><h2>Reconnecting an Account</h2><p>To restore functionality to a disconnected account, the user must go through the authentication flow again.</p><h3><strong>How it works</strong></h3><p>You generate a new auth URL using the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">/v1/social-accounts/auth-url</code> endpoint. When the user completes the login flow, the system detects the existing record and updates it with the new valid tokens, changing the status back to <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">connected</code>.</p><p></p>', 'html', NULL, false, 'published', NULL, 'cat_3idi40QLlh7LMIn3sM9mF', '2026-02-17 20:13:35.444+00', '2026-04-22 14:37:10.129547+00', '2026-04-22 14:37:10.129547+00', NULL),
	('art_7i4xCxm2M00hBCdRUUZ0', 'let-ai-post-for-you', 'Let AI Post For You', 'Let your AI assistant post to all of your accounts for you!', '<p>The <strong>Model Context Protocol (MCP)</strong> allows you to connect AI assistants, like <strong>Claude</strong> or <strong>OpenClaw</strong>, directly to your <strong>Post for Me</strong> account. By running our MCP server, you can empower AI agents to search documentation, write code, and execute social media posts on your behalf using natural language commands.</p><p>Here is a breakdown of how to set up the server and what to expect regarding AI access.</p><h2>Installation &amp; Setup</h2><p>The <strong>Post for Me MCP Server</strong> is designed to run locally or remotely, acting as a bridge between your AI client and our API.</p><h3><strong>How it works:</strong> </h3><p>You can run the server directly using <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">npx</code>. This eliminates the need for a complex installation process. You simply need to provide your <strong>API Key</strong> as an environment variable to authenticate the requests.</p><h3><strong>The Command</strong><code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">export POST_FOR_ME_API_KEY="My API Key"</code><code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">npx -y post-for-me-mcp@latest</code></h3><h3><strong>Requirements</strong> </h3><p>You must have a valid API Key from your Post for Me dashboard before starting the server.</p><h2>Client Integration</h2><p>Once the server is running, you need to configure your AI client (such as <strong>Claude Desktop</strong>, <strong>Cursor</strong>, or <strong>VS Code</strong>) to recognize the new tools.</p><h3><strong>How it works</strong></h3><p>Most clients use a configuration file (like <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">mcp.json</code> or <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">.claude.json</code>) to define available servers. You will add <strong>"post_for_me_api"</strong> to your <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">mcpServers</code> list, specifying the command and your API key in the environment settings.</p><h3><strong>The User Experience</strong> </h3><p>Once connected, you can ask your AI to "Schedule a post for Instagram next Tuesday" or "Check the analytics for my last YouTube video." The AI will utilize the <strong>Docs Search</strong> tool to understand the API and the <strong>Code</strong> tool to generate and execute the necessary TypeScript SDK code in a sandboxed environment.</p><h2>Security &amp; Access Control</h2><p>Granting an AI agent access to your API key is a powerful capability that requires careful management.</p><h3><strong>Full Access</strong> </h3><p>It is important to note that by setting up this MCP server, you are giving the AI <strong>full access to any accounts connected to your Post for Me project</strong>.</p><ul><li><p>The AI can query <strong>all</strong> social data.</p></li><li><p>The AI can publish to <strong>any</strong> connected account.</p></li><li><p>The AI can delete scheduled content.</p></li></ul><p><strong>Note:</strong> Because the agent executes code using your administrative API key, there is no "user-level" restriction. Ensure you trust the environment and the prompts you are providing to the chatbot.</p><p></p>', 'html', NULL, false, 'published', NULL, 'cat_3idi40QLlh7LMIn3sM9mF', '2026-02-13 20:00:45.06+00', '2026-04-22 14:37:10.139602+00', '2026-04-22 14:37:10.139602+00', NULL),
	('art_jR6lJhrAVhvdVXWjZvpAZ', 'real-time-updates-with-webhooks', 'Real-Time Updates with Webhooks', 'Use webhooks to get notified immediately when a post is published.', '<p><strong>Webhooks</strong> allow your application to receive real-time updates about your posts and accounts without the need to constantly poll the API.</p><p>Here is a breakdown of how to configure your webhook integrations and handle events efficiently.</p><h2>Creating a Webhook</h2><p>Currently, <strong>Webhooks</strong> can only be created and managed programmatically through the <strong>API</strong>. There is no UI for creating webhooks in the dashboard at this time.</p><h3><strong>How it works</strong> </h3><p>You make a <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">POST</code> request to the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">/v1/webhooks</code> endpoint with your public URL and the specific <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">event_types</code> you wish to subscribe to.</p><p><strong>Note</strong>: You can not create two webhooks with the same URL</p><h3><strong>The Events</strong> </h3><p>You can subscribe to the following events:</p><ul><li><p><strong>Post Events:</strong> <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">social.post.created</code>, <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">social.post.updated</code>, <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">social.post.deleted</code>, <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">social.post.result.created</code></p></li><li><p><strong>Account Events:</strong> <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">social.account.created</code>, <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">social.account.updated</code></p></li></ul><h2>Handling Requests &amp; Timeouts</h2><p>To ensure the reliability of our delivery system, your server must acknowledge receipts quickly.</p><h3><strong>The Constraint</strong> </h3><p>We expect a success response (status code <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">2XX</code>) within <strong>1 second</strong> of sending the webhook.</p><ul><li><p>If your server takes longer than <strong>1 second</strong> to respond, we consider the request failed and will schedule a retry.</p></li></ul><h3><strong>Best Practice</strong></h3><p>If your application needs to perform long-running tasks upon receiving a webhook (like database writes or sending emails), you should handle these <strong>asynchronously</strong>. Return a <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">200 OK</code> immediately to acknowledge receipt, then process the data in the background.</p><h2>Idempotency &amp; Retries</h2><p>Because webhooks are distributed systems, it is possible for your server to receive the same event multiple times.</p><h3><strong>How it works</strong> </h3><p>If a delivery fails (or times out), we utilize an <strong>exponential backoff</strong> strategy, retrying the request approximately <strong>8 times</strong> over the course of 24 hours.</p><h3><strong>The Requirement</strong> </h3><p>Your server logic should be <strong>idempotent</strong>. This means your code should be able to handle receiving the same unique event ID multiple times without creating duplicate records or unintended side effects.</p><h2>Security</h2><p>To verify that the data hitting your server is genuinely from <strong>Post for Me</strong>, we include a security header in every request.</p><h3><strong>How it works</strong> </h3><p>When you create a webhook, the API returns a unique <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">secret</code>. Every payload sent to your URL includes the header <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">Post-For-Me-Webhook-Secret</code>. Your application should always verify that this header matches your secret before processing the data.</p><p></p>', 'html', NULL, false, 'published', NULL, 'cat_3idi40QLlh7LMIn3sM9mF', '2026-02-11 16:03:48.146+00', '2026-04-22 14:37:10.148527+00', '2026-04-22 14:37:10.148527+00', NULL),
	('art_Oi6e8bEy3OBvtbycqBC5', 'getting-post-results', 'Getting Post Results', 'Understand how to see the results of your post for each account.', '<p>When you create a <strong>Post</strong> in Post for Me, you often target multiple social accounts and platforms simultaneously. To give you granular insight into the outcome of every specific publish attempt, we separate the concept of a <strong>Post</strong> from a <strong>Post Result</strong>.</p><p>Here is a breakdown of how to track the status of your content and debug issues using Post Results.</p><h2>One Post, Multiple Results</h2><p>A single <strong>Post</strong> entity acts as the container for your content, while <strong>Post Results</strong> represent the actual publication events on each platform.</p><h3><strong>How it works</strong></h3><p>If you create one Post that targets Instagram, Facebook, and LinkedIn, the system will generate <strong>three separate Post Results</strong>.</p><ul><li><p><strong>Availability:</strong> Each individual result is made available via the API as soon as that specific platform accepts or rejects the content.</p></li><li><p><strong>Parent Status:</strong> The main Post entity remains in a <strong>processing</strong> status until every single targeted account has returned a result. Once all results are in, the Post status updates to <strong>processed</strong>.</p></li></ul><h2>Using Webhooks</h2><p>While you can poll the API for updates, we <strong>highly recommend</strong> using Webhooks to receive real-time notifications when your content goes live.</p><h3><strong>How it works</strong></h3><p>By setting up a webhook, your application can listen for specific events to trigger immediate updates in your UI.</p><ul><li><p><code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">social.post.result.created</code>: Triggered immediately when a specific platform finishes processing (e.g., Facebook finishes, but Instagram is still loading).</p></li><li><p><code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">social.post.updated</code>: Triggered when the parent Post status changes (e.g., moves from <strong>processing</strong> to <strong>processed</strong>).</p></li></ul><p>This allows you to show "Published to Facebook!" checks instantly, rather than making the user wait for all platforms to finish.</p><h2>Understanding the Outcome</h2><p>Each Post Result contains detailed data fields to help you verify success or troubleshoot failures.</p><p><strong>The Data Structure:</strong></p><ul><li><p><strong>Success:</strong> A simple boolean (<code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">true</code>/<code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">false</code>) indicating if the publish attempt worked.</p></li><li><p><strong>Error:</strong> If <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">success</code> is false, this field provides a general error message explaining why the post failed (e.g., "Image aspect ratio not supported").</p></li><li><p><strong>Details:</strong> For deeper debugging, this field contains the full log of every request and response exchanged with the social platform. This is critical for developers needing to understand exactly why a platform rejected a specific payload.</p></li></ul><p></p>', 'html', NULL, false, 'published', NULL, 'cat_3idi40QLlh7LMIn3sM9mF', '2026-02-10 15:03:51.98+00', '2026-04-22 14:37:10.1602+00', '2026-04-22 14:37:10.1602+00', NULL),
	('art_KufYnueEgnloGhLmyxg5', 'tiktok-vs-tiktok-business-api', 'TikTok vs. TikTok Business API', 'Choosing between the standard TikTok and the TikTok business API. ', '<p>When integrating TikTok into your application with <strong>Post for Me</strong>, you have two distinct connection options: <strong>TikTok</strong> (Consumer) and <strong>TikTok Business</strong>. While both connection types support the ability to connect <strong>both</strong> Personal and Business accounts, they utilize different underlying APIs that offer varying levels of data depth and feature sets.</p><p>Here is a breakdown of the differences to help you choose the right integration for your users.</p><h2>Standard TikTok Connection</h2><p>The standard <strong>TikTok</strong> connection utilizes the platform''s consumer API. This is the default choice for general social posting applications.</p><h3><strong>How it works:</strong></h3><p>You initiate the connection using the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">tiktok</code> platform enum via the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">create-upload-url</code> endpoint.</p><h3><strong>The Capabilities</strong></h3><ul><li><p><strong>Posting:</strong> Full support for video publishing.</p></li><li><p><strong>Feeds:</strong> Retrieve the user''s video feed.</p></li><li><p><strong>Analytics:</strong> Provides a lightweight data set limited to the four core metrics: <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">like_count</code>, <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">comment_count</code>, <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">share_count</code>, and <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">view_count</code>.</p></li></ul><h2>TikTok Business Connection</h2><p>The <strong>TikTok Business</strong> connection utilizes the platform''s Marketing and Business API. Despite the name, this connection type can still be used to connect <strong>both</strong> Personal and Business accounts, provided the user grants the expanded permission scopes.</p><h3><strong>How it works</strong> </h3><p>You must specify the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">tiktok_business</code> platform enum when generating the auth URL. This requests a much larger set of permissions, including <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">user.insights</code> and <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">video.insights</code>,.</p><h3><strong>The Capabilities</strong></h3><ul><li><p><strong>Posting:</strong> Full support for video publishing.</p><ul><li><p><strong>Custom Thumbnails:</strong> Unlike the standard connection, the Business API allows you to upload and set custom thumbnails for video posts.</p></li></ul></li><li><p><strong>Feeds:</strong> Retrieve the user''s video feed.</p></li><li><p><strong>Advanced Analytics:</strong> Access detailed performance data including <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">total_time_watched</code>, <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">average_time_watched</code>, <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">video_view_retention</code> graphs, and audience demographics (gender, country, city),,.</p></li></ul><h2>Choosing the Right Connection</h2><p>While the <strong>TikTok Business</strong> connection offers superior features, it requests significantly more data permissions from the user which might be intimidating.</p><p><strong>Recommendation:</strong></p><ul><li><p>Use <strong>Standard TikTok</strong> if your application only requires basic posting and simple view counts.</p></li><li><p>Use <strong>TikTok Business</strong> if you are building an analytics dashboard, a marketing tool requiring deep insights, or if your users need control over video thumbnails.</p></li></ul><h4></h4><p></p>', 'html', NULL, true, 'published', NULL, 'cat_3idi40QLlh7LMIn3sM9mF', '2026-02-05 16:46:55.632+00', '2026-04-22 14:37:10.1708+00', '2026-04-22 14:37:10.1708+00', NULL),
	('art_EI77ULIQZcDq9fqWfvSKj', 'account-connections', 'Account Connections', 'Common configuration issues that can prevent successful account connections.', '<p>If you are running into issues during the authentication flow, it is likely due to a specific platform configuration or project setting.</p><p>Here is a breakdown of common connection issues and how to resolve them.</p><h2>Quickstart Project Redirects</h2><p>When using a <strong>Quickstart</strong> project, you are utilizing our system credentials to authenticate users. Because of this, you cannot dynamically override the redirect URL via the API request.</p><p>When generating the authentication link via the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">create-upload-url</code> endpoint, make sure you <strong>do not</strong> pass the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">redirect_url_override</code> parameter.</p><p>Instead of passing the URL in the code, you can set your global <strong>Project Redirect URL</strong> inside the Post for Me dashboard settings. The system will automatically redirect to this URL after a successful login.</p><h2>LinkedIn Connections</h2><p><strong>LinkedIn</strong> requires a specific connection type to enable full functionality for both personal profiles and company pages when using our shared credentials.</p><p>When creating the auth URL for a <strong>Quickstart</strong> project, you must pass <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">"organization"</code> as the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">connection_type</code>, even if the user is connecting a personal account.</p><h3>Example</h3><pre><code>{
  "platform": "linkedin",
  "platform_data": {
    "linkedin": {
      "connection_type": "organization"
    }
  },
  "permissions": [
    "posts",
    "feeds"
  ]
}</code></pre><h3><strong>Why it matters</strong></h3><p>This setting tells LinkedIn that we are requesting access via the <strong>Community Management API</strong>. This specific API allows your application to connect and manage both personal profiles and company pages under a single authentication flow.</p><h2>Facebook Requirements</h2><p><strong>Facebook</strong> permissions are strictly scoped to business usage. We cannot connect to or post to personal Facebook User Timelines.</p><p>During the connection flow, the user will be presented with a list of pages. They must select at least<strong> one Facebook page</strong> and the <strong>associated business</strong> to complete the connection.</p><p><strong>Note:</strong> If a user attempts to connect only a personal profile without selecting a Page, the connection will fail.</p><h2>Instagram Configuration</h2><p><strong>Instagram</strong> has two specific requirements regarding account types and login methods.</p><p><strong>Account Type:</strong> The target Instagram account must be converted to a <strong>Professional</strong> or <strong>Creator</strong> account. Personal Instagram accounts do not support the API features required for third-party posting.</p><p><strong>Connection Type:</strong> If you have enabled both "Instagram" and "Instagram (Facebook Login)" in your project settings, the system needs to know which flow to initiate. You must pass the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">connection_type</code> parameter with a value of either <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">"instagram"</code> or <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">"facebook"</code> to determine which login method is used.</p><h3>Example</h3><pre><code>{
  "platform": "instagram",
  "platform_data": {
    "instagram": {
      "connection_type": "instagram"
    }
  },
  "permissions": [
    "posts",
    "feeds"
  ]
}</code></pre><h2>Bluesky Authentication</h2><p><strong>Bluesky</strong> handles third-party security differently than most platforms. It does not use standard OAuth tokens in the same way; instead, it utilizes app-specific passwords.</p><p><strong>The Requirement:</strong> When connecting a Bluesky account, you must provide the <strong>handle</strong> and an <strong>App Password</strong>.</p><h3><strong>How it works</strong></h3><p>Users should not enter their standard login password. They must generate a specific App Password within their Bluesky settings and use that credential to authorize the connection.</p><p></p>', 'html', NULL, false, 'published', NULL, 'cat_3idi40QLlh7LMIn3sM9mF', '2026-02-04 20:51:47.398+00', '2026-04-22 14:37:10.181735+00', '2026-04-22 14:37:10.181735+00', NULL),
	('art_5nCk8nsR4mifPa6rZkrh', 'understanding-metric-variance', 'Understanding Metric Variance', 'Understand any possible metric variance between the API and the platform''s native app.', '<p>When fetching analytics with <strong>Post for Me</strong>, you may notice discrepancies between the data returned through the API and the numbers displayed directly on a social platform''s native app. These variances are normal and occur because platforms process, verify, and serve third-party API data differently than they serve real-time user counters.</p><p>Ultimately we <strong>do not process</strong> any of the metrics returned from the platforms, rather the metrics are always the <strong>current life time value </strong>returned <strong>directly</strong> from the platforms'' API. Any variance that occurs is due to differences in how the platform treats their API and Native App.</p><p>Here is a breakdown of why these variances occur and how to interpret the data across supported platforms.</p><h2>Processing Delays &amp; Granularity (Meta)</h2><p><strong>Facebook</strong> and <strong>Instagram</strong> often show variance due to strict processing windows and data definitions that differ from the simplified "View" counts seen on a timeline.</p><h3><strong>The Delay</strong> </h3><p>While the Instagram mobile app might show a new "Like" instantly, the API serves verified data which undergoes processing.</p><p>
<strong>Note:</strong> Metrics for <strong>Instagram</strong> may take up to <strong>48 hours</strong> to become fully available or accurate via the API. Additionally only data will only be stored for 2 years.</p><h3><strong>The Variance</strong></h3><ul><li><p><strong>Facebook Views:</strong> The native newsfeed aggregates views into a single number. The API breaks this down into specific segments like <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">video_views_autoplayed</code>, <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">video_views_clicked_to_play</code>, and <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">video_views_unique</code>.</p></li><li><p><strong>Privacy Thresholds:</strong> Detailed demographic data (e.g., age/gender breakdowns) will not be returned by the API if the count is below a specific privacy threshold, even if the total view count is visible.</p></li><li><p><strong>In Development:</strong> Certain metrics like <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">views</code> are listed by <strong>Instagram</strong> as “in development”. This means they are constantly changing how they calculate this metric to find the best way to represent the value accurately. It is not guaranteed that the calculation method will be the same between the native app and the API.</p></li><li><p><strong>Organic Only:</strong> The API will only return organic metrics, any interactions on media from an AD will not be returned.</p></li></ul><h2>Definitions &amp; Estimation (YouTube &amp; X)</h2><p>Some platforms use different definitions for API data to separate organic performance from paid or premium traffic.</p><h3><strong>YouTube</strong></h3><ul><li><p><strong>Premium Views:</strong> The API distinguishes standard views from <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">redViews</code> (views from YouTube Premium members).</p></li><li><p><strong>Estimation:</strong> Metrics like <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">estimatedMinutesWatched</code> are calculated values that may lag behind the real-time "Views" counter while YouTube verifies traffic sources.</p></li></ul><h3><strong>X (Twitter)</strong></h3><ul><li><p><strong>Data Buckets:</strong> X separates metrics into <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">public_metrics</code>, <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">organic_metrics</code>, and <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">non_public_metrics</code> (promoted).</p></li><li><p><strong>The Variance:</strong> A "Public" impression count on a tweet includes both organic and paid traffic. The API allows you to display these separately, which may result in your dashboard showing a lower "Organic" number than the user sees on the tweet footer.</p></li></ul><h2>Platform Specific Constraints</h2><p>Certain platforms have hard restrictions that result in <strong>zero data</strong> being returned for specific configurations.</p><h3><strong>The Constraints</strong></h3><ul><li><p><strong>LinkedIn:</strong> Metrics are exclusively available for <strong>Company Pages</strong>. LinkedIn does not currently permit analytics access for personal profiles.</p></li><li><p><strong>Bluesky:</strong> Bluesky does not currently expose view counts or impressions via their API. While other metrics may appear, "Views" will always be unavailable.</p></li></ul><p></p>', 'html', NULL, false, 'published', NULL, 'cat_3idi40QLlh7LMIn3sM9mF', '2026-02-04 15:21:29.876+00', '2026-04-22 14:37:10.192074+00', '2026-04-22 14:37:10.192074+00', NULL),
	('art_oSa6GYbhVsifzURjawTw9', 'multi-user-applications', 'Multi-User Applications', 'Use external id to easily manage multiple users connecting their accounts.', '<p>When building a <strong>SaaS platform</strong> or <strong>multi-tenant application</strong> with <strong>Post for Me</strong>, ensuring that users only access their own social accounts is critical. Since your <strong>API Key</strong> provides administrative access to your entire project, it must remain secure on your <strong>backend</strong> and never be exposed to client-side code.</p><p>Here is a breakdown of how to safely manage user access using <strong>External IDs</strong> and handle account connection workflows.</p><h2>Server-Side Security</h2><p>Your <strong>Post for Me</strong> API key is a project level credential. It grants full control over every connected account and post within your project.</p><h3><strong>How it works</strong></h3><p>All API requests should originate from your secure server. Your frontend client should never make calls directly to the Post for Me API.</p><p><strong>Requirement:</strong> Ensure your API keys are stored in environment variables on your backend service.</p><h2>Mapping Users with External IDs</h2><p>To separate user data within a single project, you can use the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">external_id</code> parameter. This allows you to map a social account in our system directly to a User or Tenant ID in your database.</p><h3><strong>How it works</strong></h3><p>When generating an authentication URL via the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">/v1/social-accounts/auth-url</code> endpoint, you pass your internal user''s ID as the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">external_id</code>.</p><h3><strong>The Workflow</strong></h3><ol><li><p><strong>Connect:</strong> Pass <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">external_id: "user_123"</code> when creating the auth URL.</p></li><li><p><strong>Filter:</strong> When fetching accounts for that user, verify ownership by filtering the request: <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">GET /v1/social-accounts?external_id=user_123</code>.</p></li><li><p><strong>Post:</strong> When creating a post, you can verify the user owns the target accounts by checking their associated <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">external_id</code>.</p></li></ol><h2>The Account Selection Flow</h2><p>When a user authenticates with a social platform, <strong>Post for Me</strong> automatically imports <strong>every account</strong> that user has access to.</p><p><strong>For example</strong>: If a user logs into <strong>LinkedIn</strong>, we will connect their personal profile <em>and</em> every Company Page they manage. All of these accounts will be assigned the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">external_id</code> you provided during the initial request.</p><p>If you would like to let the user select which accounts they want to select, then you will need to handle that in your app after we connect the accounts and redirect to you. Following a similar workflow to what is detailed below:</p><h3>Selection Workflow</h3><ol><li><p><strong>Redirect:</strong> After authentication, we redirect the user to your app with the new Account IDs.</p></li><li><p><strong>Fetch &amp; Display:</strong> Use the IDs to fetch account details (names, profile pictures).</p></li><li><p><strong>Confirm:</strong> Present a modal asking the user, "Which accounts do you want to connect?"</p></li><li><p><strong>Cleanup:</strong> Call the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">/disconnect</code> endpoint to remove any accounts the user did not select.</p></li></ol><h2>Handling Shared Accounts</h2><p><strong>Post for Me</strong> does not allow duplicate accounts within a single project.</p><h3><strong>How it works:</strong></h3><p>If "User A" connects a specific Facebook Page, and later "User B" connects that <em>exact same</em> Facebook Page, we will update the existing record rather than creating a new one.</p><p><strong>Note:</strong> If your application allows multiple users to manage the same social account (e.g., a shared business page used by a marketing team), your application must manage the mapping. You will need to maintain a table in your database linking your internal <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">user_ids</code> to our single <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">social_account_id</code>.</p><p></p>', 'html', NULL, false, 'published', NULL, 'cat_3idi40QLlh7LMIn3sM9mF', '2026-02-02 18:18:03.33+00', '2026-04-22 14:37:10.201464+00', '2026-04-22 14:37:10.201464+00', NULL),
	('art_6pTt1Y5aHxY8q4Dv7jGH1', 'posting-media', 'Posting Media', 'Posting media is simple whether using your own hosted files or our free storage solution.', '<p>When creating posts with <strong>Post for Me</strong>, attaching images or video is straightforward. Ultimately, the API just requires a valid <strong>media URL</strong> to fetch your content. You can provide this URL in two ways: using your <strong>own hosting </strong>or utilizing our <strong>temporary storage</strong>.</p><p>Here is a breakdown of how to handle media assets for your posts.</p><h2>Bring Your Own Storage</h2><p>If your media is <strong>already hosted</strong> online, you can use it directly without any additional API calls.</p><h3><strong>How it works</strong></h3><p>Simply pass a publicly accessible URL (e.g., from an AWS S3 bucket, Cloudinary, or your own server) into the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">media</code> array when creating a post. This URL should return the actual binary data of the file and not an html page, video player, etc.. The Post for Me API will fetch the asset from this URL during the publishing process. Similarly a separate thumbnail URL can be provided if you have a dedicated image to use for the thumbnail of your video.</p><p><strong>Note</strong>: thumbnail URLs are only supported for Facebook, Instagram, TikTok Business, and YouTube accounts.</p><h3><strong>Requirements</strong></h3><p>The URL must be publicly accessible so our servers can retrieve the file at the time of posting and must and image or video file.</p><h2>Temporary Storage</h2><p>If your application does not host media files, you can use our <strong>temporary storage</strong> to stage your assets before publishing.</p><h3><strong>How it works</strong></h3><p>This involves a simple three-step sequence:</p><ol><li><p><strong>Generate URLs:</strong> Make a <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">POST</code> request to the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">/v1/media/create-upload-url</code> endpoint. This returns two values: a signed <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">upload_url</code> (for uploading the file) and a public <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">media_url</code> (for referencing the file).</p></li><li><p><strong>Upload the File:</strong> Upload your file binary directly to the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">upload_url</code> using a <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">PUT</code> request.</p></li><li><p><strong>Create the Post:</strong> Use the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">media_url</code> returned in step 1 when calling the post creation endpoint.</p></li></ol><p><strong>Note:</strong> The <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">upload_url</code> is a signed URL valid for a short time, so files should be uploaded immediately after generating the URL.</p><p>Repeat the above process for any media you wish to include in a post, including thumbnail URLs where applicable.</p><h2>Media Lifecycle</h2><p>Our storage system is designed to be ephemeral. It holds your assets only as long as necessary to complete the publishing process.</p><h3><strong>Automatic Cleanup</strong></h3><p>Media assets stored in our system are automatically deleted in the following scenarios:</p><ul><li><p>Immediately when the associated post is <strong>published</strong>.</p></li><li><p>When a scheduled post containing the media is <strong>deleted</strong>.</p></li><li><p>After <strong>24 hours</strong> if the uploaded media has not been attached to any post.</p></li></ul><h2>Media Processing</h2><p>Media is only processed if the attached file does not meet the platform’s requirements to be posted. For example if an image or video file is too large then we will compress it down to the largest allowed size in order for it to be successfully published.</p><p>We will never water mark or alter the content in any way other then the minimum processing required to publish the content</p><p><strong>Note</strong>: By default our media pipelines are engineered for short form content, if you are intending to post very large long form files through our API please contact us so we can better accommodate your use case.</p><p></p>', 'html', NULL, true, 'published', NULL, 'cat_3idi40QLlh7LMIn3sM9mF', '2026-01-31 03:27:38.286+00', '2026-04-22 14:37:10.211346+00', '2026-04-22 14:37:10.211346+00', NULL),
	('art_z6fmGr1WjfOS3dQKjApCB', 'advanced-posting-configurations', 'Advanced Post Configurations', 'Customize posts exactly how you want by using our simple but powerful configuration options.', '<p>When creating a standard post with <strong>Post for Me</strong>, the basics are simple: you need a <strong>caption</strong>, optional <strong>media</strong>, and the target <strong>social accounts</strong>. However, when you need granular control over how content appears on specific networks, we offer two powerful tools: <strong>platform_configurations</strong> and <strong>account_configurations</strong>.</p><p>Here is a breakdown of how to utilize overrides to customize your posting flow.</p><h2>The Cascading Logic</h2><p>Just like CSS, the Post for Me API applies settings in a cascading style where the <strong>most specific configuration</strong> takes precedence.</p><h3><strong>How it works</strong></h3><p>The system checks for settings in the following order:</p><ol><li><p><strong>Account Configuration</strong> (Highest Priority)</p></li><li><p><strong>Platform Configuration</strong></p></li><li><p><strong>Base Post</strong> (Lowest Priority)</p></li></ol><h3>Example</h3><p>If you set a generic caption on the base post, a specific caption in <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">platform_configurations</code>, and a third caption in <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">account_configurations</code>, the <strong>account configuration caption</strong> will be the one published to that specific account.</p><h2>Platform Configurations</h2><p><strong>Platform configurations</strong> allow you to set overrides and details that apply to <strong>all accounts</strong> of a specific platform included in the post request.</p><h3><strong>How it works</strong></h3><p>You pass a <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">platform_configurations</code> object containing keys for the specific networks (e.g., <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">tiktok</code>, <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">youtube</code>, <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">instagram</code>). Any setting defined here will automatically apply to every account matching that platform type.</p><h3><strong>Use Case</strong></h3><p>This is ideal for ensuring all TikTok uploads have comments enabled, or ensuring all Instagram posts are published as Reels rather than timeline posts. Additionally if you want all Instagram accounts to have a slightly different caption then all of the TikTok ones then this is how you would do it.</p><h2>Account Configurations</h2><p><strong>Account configurations</strong> provide the highest level of specificity, allowing you to set overrides for a single, specific <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">social_account_id</code>.</p><h3><strong>How it works</strong></h3><p>You pass an array of objects, each specifying a <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">social_account_id</code> and a <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">configuration</code> object. These settings will only apply to that exact account.</p><h3><strong>Use Case</strong></h3><p>Use this when you are posting to multiple accounts on the same platform but need different settings for each. For example, if one Instagram account needs to tag a specific collaborator, while another does not.</p><h2>Advanced Configuration Options</h2><p>You can set a wide variety of platform-specific options under both the <strong>platform_configurations</strong> and <strong>account_configurations</strong>. Here are a few powerful examples:</p><ul><li><p><strong>TikTok:</strong> Set a specific <strong>title</strong>, control <strong>privacy_status</strong> (public/private), or manage engagement settings like <strong>allow_duet</strong> and <strong>allow_comment</strong>.</p></li><li><p><strong>YouTube</strong>: Set a specific <strong>title</strong>, control <strong>privacy_status</strong>, or indicate if the video was <strong>made_for_kids</strong></p></li><li><p><strong>Instagram:</strong> Define the <strong>placement</strong> (Reels vs. Stories), tag <strong>collaborators</strong>, or specify the <strong>trial_reel_type</strong> (manual or performance).</p></li><li><p><strong>Facebook:</strong> Control <strong>placement</strong> (Reels vs. Timeline) or add <strong>location</strong> tags to your posts.</p></li><li><p><strong>Pinterest:</strong> Assign specific <strong>board_ids</strong> or set a custom destination <strong>link</strong> for the pin.</p></li></ul><p>For a complete list of every available parameter for each platform, please refer to the documentation.</p><p></p>', 'html', NULL, true, 'published', NULL, 'cat_3idi40QLlh7LMIn3sM9mF', '2026-01-31 03:27:38.286+00', '2026-04-22 14:37:10.220935+00', '2026-04-22 14:37:10.220935+00', NULL),
	('art_d6ULXyM5TToZT5EIPr2', 'getting-post-analytics', 'Getting Post Analytics', 'Get analytics data for any post published to your account using our social account feed endpoint.', '<p>When managing social media integrations, tracking the performance of content is just as important as publishing it. <strong>Post for Me</strong> provides a unified way to retrieve comprehensive analytics across supported platforms through the <strong>Social Account Feed</strong>.</p><p>Here is a breakdown of how to configure your connections and retrieve metrics for your users'' posts.</p><h2>The Social Account Feed</h2><p>Analytics data is not housed in a separate "analytics" endpoint; instead, it is integrated directly into the <strong>Social Account Feed</strong> endpoint.</p><h2><strong>How it works</strong></h2><p>This endpoint allows you to fetch the feed for any connected social account. This will include <strong>every post</strong> on that account, regardless of whether it was published through the Post for Me API or natively through the social platform. When enabled, the response includes detailed metrics such as views, likes, shares, and follows, alongside standard post information like captions and media URLs,.</p><h3>Connection Requirements</h3><p>To access feed data and metrics, you must ensure the social account is connected with the correct permissions. When generating an authentication URL using the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">create-upload-url</code> flow (specifically the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">/v1/social-accounts/auth-url</code> endpoint), you must explicitly request the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">"feeds"</code> permission in the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">permissions</code> array.</p><p><strong>Note:</strong> If an account is connected with only the default <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">"posts"</code> permission, requests to the feed endpoint will not return data,.</p><h3>Retrieving Metrics</h3><p>Once an account is connected with the proper permissions, retrieving analytics is a single API call.</p><p>Make a <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">GET</code> request to the <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">/v1/social-account-feeds/{social_account_id}</code> endpoint. To include analytics data in the response, you must pass the optional <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">expand</code> parameter with the value <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">metrics</code>.</p><p><strong>Example Call:</strong><code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">GET /v1/social-account-feeds/spc_12345?expand=metrics</code></p><h2>Understanding the Data</h2><p>The metrics returned by the API represent the <strong>current lifetime value</strong> of the metric for that specific post.</p><h3><strong>Platform Specifics</strong></h3><p>The specific data points returned depend heavily on the platform''s API capabilities. For example:</p><ul><li><p><strong>Detailed Metrics:</strong> Platforms like <strong>TikTok</strong> and <strong>Facebook</strong> provide extensive details, including total time watched, engagement rates, and impression sources,.</p></li><li><p><strong>Standard Metrics:</strong> <strong>Instagram</strong> and <strong>X (Twitter)</strong> provide standard counts for likes, comments, views, and shares,.</p></li><li><p><strong>Limitations:</strong> Some platforms, such as <strong>LinkedIn</strong>, only allow analytics for Company Pages (metrics for personal pages are currently unavailable). Similarly, <strong>Bluesky</strong> does not currently expose view counts through their API.</p></li></ul><p>For a complete list of available metrics per platform, please refer to the specific response objects in the documentation</p><h4></h4><p></p>', 'html', NULL, true, 'published', NULL, 'cat_3idi40QLlh7LMIn3sM9mF', '2026-01-29 21:07:52.614+00', '2026-04-22 14:37:10.229117+00', '2026-04-22 14:37:10.229117+00', NULL),
	('art_KKVCKLN8l7AJ813aMi0ie', 'quickstart-vs-white-label-project', 'Quickstart vs. White Label Project', 'When creating a new project on Post for Me, you will need to choose between two project types: Quickstart and White Label.', '<p>When creating a new project on <strong>Post for Me</strong>, you will need to choose between two project types: <strong>Quickstart</strong> and <strong>White Label</strong>. While the code integration and platform support remain the same for both, they differ significantly in how the social platforms are configured and what your end users see during the account connection process.</p><p>Here is a breakdown of the differences to help you decide which is best for your use case.</p><h2>Quickstart Projects</h2><p><strong>Quickstart</strong> projects are designed so you can start posting immediately. They allow you to utilize our approved social app credentials. This means you do not need to create your own developer accounts with platforms like LinkedIn, X (Twitter), or Facebook, nor do you need to submit your app for review.</p><ul><li><p><strong>How it works:</strong> Simply enable the desired platforms in the Post for Me dashboard. You can start connecting accounts and posting immediately.</p></li><li><p><strong>The User Experience:</strong> When your users go through the OAuth flow to connect their social accounts, they will see the <strong>"Post for Me"</strong> brand and logo requesting permission to access their account.</p></li><li><p><strong>Best for:</strong> Internal tools, prototypes, MVPs, or applications where white-labeling is not a strict requirement.</p></li></ul><p>You still have full access to the accounts connected, however the connections will go through our app credentials and will be subject the permissions that our app has been approved for.</p><h2>White Label Projects</h2><p><strong>White Label</strong> projects are designed for production applications where brand consistency is paramount. This project type allows you to use your <em>own</em> social app credentials.</p><ul><li><p><strong>How it works:</strong> You must set up developer accounts and create applications on each social platform you wish to support. You will then input your specific Client IDs and Secrets into the Post for Me dashboard. We have separate getting started guides for each platform to help with this process.</p></li><li><p><strong>The User Experience:</strong> When your users connect their accounts, they will see <strong>Your App Name</strong> and <strong>Your Logo</strong> during the authorization process. There will never be any mention of <strong>Post for Me</strong> to your users.</p></li><li><p><strong>Requirements:</strong> Because you are using your own credentials, your app must go through the approval and verification processes mandated by each specific social network. If you want help walking through this process feel free to reach out!</p></li><li><p><strong>Advanced Features:</strong> White Label projects offer more granular control over the OAuth process, including the ability to pass permission overrides and custom redirect URLs.</p></li></ul><p>Since these projects use your own app credentials, you can ask for additional permissions that your app has been approved for. Allowing more advanced integrations with the social platforms outside of the available Post for Me endpoints.</p><h2>Common Ground</h2><p>Despite the differences in setup, the core functionality of the API remains identical:</p><ol><li><p><strong>Seamless Integration:</strong> The code required to integrate Post for Me does not change based on the project type. You can switch strategies without rewriting your backend logic.</p></li><li><p><strong>Full Platform Support:</strong> All social platforms supported by Post for Me are available on both Quickstart and White Label projects.</p></li></ol><h2>Mixing and Matching</h2><p>You are not locked into one type of project for your entire account. You can mix and match project types to suit your development lifecycle.</p><p>For example, you might create a <strong>Quickstart</strong> project for your development or staging environment to test features quickly, while using a <strong>White Label</strong> project for your production environment to ensure a branded experience for your customers.</p><p><strong>Note:</strong> Each project has its own unique <code class="rounded-md bg-muted px-1.5 py-1 font-medium font-mono">API_KEY</code>. If you use different project types for different environments, ensure you are managing your API keys accordingly in your application configuration.</p><p></p>', 'html', NULL, true, 'published', NULL, 'cat_3idi40QLlh7LMIn3sM9mF', '2026-01-21 18:21:05.002+00', '2026-04-22 14:37:10.248089+00', '2026-04-22 14:37:10.248089+00', NULL),
	('art_CjIXkiMxYBCHo6QRFWxpf', 'turning-player-achievement-into-organic-growth-for-your-mobile-game', 'Turning Player Achievement into Organic Growth for your Mobile Game', 'The secret to scaling mobile game marketing in 2026 isn''t a bigger budget; it''s reducing player sharing friction to zero. Here’s how to turn "Boss Kills" into your most profitable marketing channel.', '<p>For those building mobile games, there is a persistent tension between two equally necessary areas of focus: crafting immersive player experiences that excite players and the strategic marketing of user acquisition.</p><p>It is a difficult balance to maintain. In the early stages, it can be frustrating to see a high-quality project buried by social media platform algorithms. At scale, that frustration often evolves into a financial weight, feeling trapped in a cycle of feeding expensive ads.</p><p>In today''s landscape, traditional marketing isn''t just a budget line item; it is a barrier that often feels disconnected from the actual joy of the game. You can’t bring in new players without it, but spending time on it takes away from the thing you love most: making a killer game.</p><h2>The Scaling Wall: When Traditional UA Falters</h2><p>The current environment for mobile growth is reaching a point of diminishing returns. Industry benchmarks for 2026 highlight a reality that is increasingly difficult for studios to navigate:</p><ul><li><p><strong>Prohibitive Entry Costs:</strong> Cost Per Install (CPI) is no longer a minor hurdle. In competitive markets, studios are seeing CPIs ranging from <strong>$2.50–$5.00+ on iOS</strong> and exceeding <strong>$3.25 on Android</strong> <a target="_blank" href="https://megadigital.ai/en/blog/cpi-mobile-game-guide/"><em>(Mega Digital CPI Mobile Game Guide, 2026 projections)</em></a>.</p></li><li><p><strong>The Thinning "Halo Effect":</strong> Developers often rely on paid ads to trigger "organic spillover". Basically, free installs resulting from higher store rankings built over time by paid ads. <a target="_blank" href="https://arxiv.org/abs/2504.16151"><em>(Complementarity Between Paid and Organic Installs in Mobile App Advertising, arXiv:2504.16151v1, April 2025)</em></a>.</p></li></ul><p>For a creative team, this creates a high-stakes environment where growth feels dependent on budgets rather than the quality of the game itself. There is, however, an opportunity to bridge this gap by focusing on the one thing ads cannot replicate: <strong>the player’s authentic excitement.</strong></p><hr /><h2>Capturing the Spark of Achievement</h2><p>A player-centric approach aligns marketing with the game’s creative health. High-value players are inherently social; they don''t just want to play, they want to be part of a community.</p><p>The most potent marketing for a game isn''t a polished trailer; it is the moment a player finally conquers a hard boss or unlocks a rare item. In that moment, the player is experiencing the core joy the developer intended.</p><p>I don’t think it’s outlandish to say that most players have a natural impulse to share their victories, <strong>but that impulse is fragile. </strong>If a player must take a screenshot, minimize the app, open a social network, and manually compose a post, the friction is almost always too high. The "magic" of the win evaporates during the process. <strong>To turn these moments into growth, a we need to reduce that friction to near zero.</strong></p><h3>Automating "Bragging Rights"</h3><p>By integrating sharing as a seamless feature of the gameplay rather than an external chore, studios can turn players into advocates without asking them to “do the work".</p><p>Posting <strong>Stories</strong> (Instagram/Facebook) to user’s accounts shares these winning moments in a timely manner. They disappear in 24 hours. This reduces "social risk" of cluttering a permanent feed while reaching their personal network where trust is highest.</p><p>A one-time ask to a user to connect their social accounts, encouraged by a meaningful reward like premium currency or a unique badge, sets the stage for effortless sharing.</p><p>And over time, you can turn these sharable moments into an interactive feature of the game. Give players the option to add a reaction selfie or a 15-second gameplay clip ensures the content feels like a personal milestone rather than a corporate advertisement.</p><hr /><h2>Moving Toward a Sustainable Growth Model</h2><p>Shifting away from a total dependence on paid ads doesn''t require a pivot in game design. Instead, it requires identifying the high-emotion triggers that <em>already exist</em> in the game and giving them a megaphone.</p><p>Infrastructure tools like <a target="_blank" href="https://www.postforme.dev"><strong>Post for Me</strong></a> are designed to handle the technical complexities of these social integrations. <strong>By automating the sharing pipeline, they allow the development team to stay focused on the fun of the game while enabling the marketing team to leverage organic, player-driven reach to scale outreach without breaking budgets.</strong></p><p>The tension between building a game and marketing it may always exist, but it becomes manageable when a studio empowers its players to do the talking. A player’s celebration isn''t just a social post, it''s the most efficient growth engine available.</p><h3>So where do we go from here?</h3><p>If you''re looking to share this strategy with your team, use this as a guide to unlock opportunities to grow organic outreach using player achievements:</p><ol><li><p><strong>Identify Triggers:</strong> List the top 3 "High-Emotion" moments in your game (e.g., Level ups, Boss kills, Legendary drops).</p></li><li><p><strong>Audit Friction:</strong> Count the steps a player currently takes to share a win. If it''s more than two, it''s too many.</p></li><li><p><strong>Define the Incentive:</strong> Choose a reward for the initial social link that is valuable but doesn''t break the game economy.</p></li><li><p><strong>Select Platforms:</strong> Start with short-lived Story formats to minimize social friction for the user.</p></li><li><p><strong>Infrastructure Check:</strong> Decide if you will build the social API pipelines in-house or use a tool like <a target="_blank" href="https://www.postforme.dev"><strong>Post for Me</strong></a> to handle the automation.</p></li></ol><p></p>', 'html', 'https://images.marblecms.com/media/2hI_DneOkte3uNzGcaw7d.png', false, 'published', NULL, 'cat_h4EdiGZ3bFBa4O4dHm1O6', '2026-01-20 18:37:09.421+00', '2026-04-22 14:37:10.576282+00', '2026-04-22 14:37:10.576282+00', NULL),
	('art_y00faRXurRyqpK6HLtbmB', 'start-building-integrations-with-tiktok-instagram-youtube-facebook-and-more', 'Start Building Integrations with TikTok, Instagram, YouTube, Facebook, and more', 'Post for Me is the unified developer API that simplifies social media integrations. Post and schedule content to TikTok, Instagram, Facebook, YouTube, X (Twitter), LinkedIn, Threads, Pinterest, and Bluesky with one simple REST endpoint. Handle OAuth, media processing, feeds, analytics, and webhooks effortlessly—no more platform-specific headaches or months of custom code.', '<div><iframe allowfullscreen="true" src="https://www.youtube.com/embed/3CAZhwUdtfw?rel=1"></iframe></div><p>There’s so much you can do when users connect their social media accounts directly to your app. Auto-posting AI-generated videos to TikTok, scheduling event promos on Facebook and Instagram, or pulling analytics into a dashboard for LinkedIn and X. But building these integrations is daunting and quickly turns into a maze of platform-specific API requirements, each with its own authentication, media, and approval requirements that eat up more budget and time than they should.</p><p>I''ve led integrations for clients (at our dev agency, <a target="_blank" href="https://www.daymoon.dev">Day Moon</a>) that needed reliable posting, scheduling, feeds, and analytics features across multiple networks. The existing tools out there were geared more toward team schedulers than developers. We needed to embed scalable features into products, and existing solutions quickly became limited and cost prohibitive. We were stuck building our own integrations, and kept rebuilding similar logic project after project, rewriting and sharing the edge cases of unique OAuth flows, media processing requirements, failure handling and scheduling infrastructure.</p><p>After enough frustration, we decided to just fix the problem ourselves. That''s how Post for Me was born: a unified API that takes all the complexity of social media integrations off your plate. Now, with one REST endpoint, you can connect user accounts, post text, images, or videos instantly or on a schedule, validate and process media automatically, fetch feeds, and retrieve analytics (views, likes, shares, engagement) across all of the major platforms: TikTok, Instagram, Facebook, YouTube, X (Twitter), LinkedIn, Threads, Pinterest, and Bluesky.</p><p>OAuth flows start with a single API call. Webhooks give real-time updates when posts land. SDKs for <a target="_blank" href="https://github.com/DayMoonDevelopment/post-for-me-typescript">TypeScript</a>, <a target="_blank" href="https://github.com/DayMoonDevelopment/post-for-me-python">Python</a>, <a target="_blank" href="https://github.com/DayMoonDevelopment/post-for-me-go">Go</a>, <a target="_blank" href="https://github.com/DayMoonDevelopment/post-for-me-ruby">Ruby</a>, and <a target="_blank" href="https://github.com/DayMoonDevelopment/post-for-me-kotlin">Kotlin</a> make integration seamless. The codebase is even <a target="_blank" href="https://github.com/DayMoonDevelopment/post-for-me">open source on GitHub</a> so you can review it or contribute.</p><p>We offer ways to get started to fit your needs:</p><ul><li><p><strong>Quickstart Project</strong>: This uses our pre-approved developer credentials so you don’t have to wait for platform approvals. Great for prototypes, internal tools, early testing, and vibe-coded apps.</p></li><li><p><strong>White Label Project</strong>: Get approved on each platform and bring your own developer credentials so users see <strong>your</strong> brand name in the OAuth flow. Perfect for SaaS products, mobile apps, or anything where consistent branding matters.</p></li></ul><p>Every project offers <strong>unlimited account connections</strong>, <strong>unlimited feed reads</strong>, <strong>unlimited analytics</strong>, and <strong>no artificial caps</strong> on growth or team size. <a target="_blank" href="https://www.postforme.dev/pricing">Pricing is straightforward</a> and scales with you, offering predictable tiers and enterprise options for high volumes.</p><p>There’s so much you can build when the integrations are taken off your plate:</p><ul><li><p>AI content tools that generate and distribute posts across networks automatically.</p></li><li><p>Event management apps that schedule promotions to TikTok videos, Instagram stories, and Facebook pages.</p></li><li><p>Games letting players share achievements on X and LinkedIn.</p></li><li><p>Marketing dashboards for agencies to manage client feeds and track performance in one place.</p></li><li><p>E-commerce platforms auto-sharing products to Pinterest and Threads.</p></li><li><p>CRMs or news apps pulling in social analytics alongside your own data.</p></li></ul><p>If you''re ready to add powerful social features without derailing your roadmap, <a target="_blank" href="https://app.postforme.dev">sign up for your account today</a>. Create a project, follow the docs, and start connecting accounts. You''ll be shipping in hours, weeks.</p><p>Happy hacking.</p>', 'html', 'https://images.marblecms.com/media/5Lo8FwlvX4CCdlWCy5ClE.png', false, 'published', NULL, 'cat_h4EdiGZ3bFBa4O4dHm1O6', '2026-01-12 19:57:38.674+00', '2026-04-22 14:37:10.714721+00', '2026-04-22 14:37:10.714721+00', NULL),
	('art_118NVHY93c2G3R8fCrXa', 'getting-started-with-the-youtube-api', 'YouTube API', 'Step-by-step guide for posting to YouTube through the Post For Me API', '<h1>YouTube (Google) Integration Guide</h1>
<p>This guide shows you how to configure a Google Developer App to enable YouTube integrations in <strong>Post For Me</strong>, allowing users to schedule and publish videos to their YouTube channels. Feel free to contact us at <a href="mailto:postforme@daymoon.dev">postforme@daymoon.dev</a> for any additional support!</p>
<hr />
<h2>Prerequisites</h2>
<ul>
<li>A valid <strong>Google account</strong></li>
<li>A <strong>Google Cloud project</strong> ready for API usage</li>
</ul>
<hr />
<h2>1. Enable YouTube Data API</h2>
<ol>
<li>Go to the <a href="https://console.cloud.google.com/">Google Cloud Console</a> and select your project.</li>
<li>Navigate to <strong>APIs &amp; Services → Enable APIs and Services</strong>.</li>
<li>Search for <strong>YouTube Data API v3</strong> and click <strong>Enable</strong>.</li>
</ol>
<hr />
<h2>2. Create OAuth Credentials</h2>
<ol>
<li><p>Within <strong>APIs &amp; Services</strong>, open the <strong>Credentials</strong> tab and click <strong>Create Credentials → OAuth client ID</strong>.</p>
</li>
<li><p>If prompted, configure the <strong>OAuth consent screen</strong> (see Section 3).</p>
</li>
<li><p>Choose <strong>Web application</strong> as the Application type.</p>
</li>
<li><p>Fill in the App name.</p>
</li>
<li><p>Under <strong>Authorized redirect URIs</strong>, add:<code>https://app.postforme.dev/callback/&lt;project_id&gt;/youtube/account</code></p>
<ul>
<li>Replace <code>&lt;project_id&gt;</code> with your actual Post For Me project ID or copy the full URL from the configure section</li>
</ul>
</li>
<li><p>Click <strong>Create</strong> to generate the credentials.</p>
</li>
</ol>
<hr />
<h2>3. Configure OAuth Consent Screen</h2>
<ol>
<li>Under <strong>APIs &amp; Services → OAuth consent screen</strong>, configure your OAuth app settings:<ul>
<li><strong>User type</strong>: Select <em>External</em> if Post For Me is used by multiple customers, otherwise <em>Internal</em> for team-only usage.</li>
<li>Enter required info such as <strong>App name</strong>, <strong>Support email</strong>, <strong>Logo</strong>, <strong>Privacy Policy URL</strong>, and <strong>Homepage URL</strong>.</li>
</ul>
</li>
<li>Add these scopes:<ul>
<li><code>https://www.googleapis.com/auth/youtube</code></li>
<li><code>https://www.googleapis.com/auth/youtube.upload</code></li>
</ul>
</li>
<li>If you selected <em>External</em>, add any test-user emails under <strong>Test users</strong>.</li>
<li>Save and finalize the consent screen.</li>
</ol>
<hr />
<h2>4. Copy OAuth Credentials to Post For Me</h2>
<ol>
<li>After creation, copy the <strong>Client ID</strong> and <strong>Client Secret</strong> from the credentials page.</li>
<li>In <strong>Post For Me</strong>, go to: Configure -&gt; YouTube</li>
<li>Paste the Client ID and Secret into their respective fields.</li>
</ol>
<hr />
<h2>5. Connect a YouTube Account</h2>
<ol>
<li>In <strong>Post For Me</strong>, go to: Project -&gt; Social Media Accounts -&gt; Connect an Account</li>
<li>Choose <strong>YouTube</strong>.</li>
<li>Follow the Google OAuth flow to connect a channel.</li>
</ol>
<hr />
<h2>6. Handle Token Expiration (Especially in Testing)</h2>
<p>Google limits refresh tokens to <strong>7 days</strong> if the OAuth consent screen is in <em>Testing</em> mode. To avoid frequent token expiration:</p>
<ul>
<li>Switch your OAuth consent screen to <strong>Production</strong> after testing.</li>
</ul>
<hr />
<h2>7. Manage Quotas (Optional)</h2>
<p>YouTube API usage is subject to quota limits:</p>
<ol>
<li>In the Cloud Console, go to <strong>APIs &amp; Services → Enabled APIs &amp; services → YouTube Data API v3</strong>.</li>
<li>View your quota usage and request increases if needed (after completing required security audits).</li>
</ol>
<hr />
<h2>Done!</h2>
<p>Your integration is live! YouTube accounts connected via Post For Me are now able to schedule and publish videos seamlessly.</p>
', 'html', NULL, false, 'published', NULL, 'cat_3idi40QLlh7LMIn3sM9mF', '2025-12-16 02:46:03.906+00', '2026-04-22 14:37:10.722761+00', '2026-04-22 14:37:10.722761+00', NULL),
	('art_Gyr6I41rWdL1EoZpDPlsL', 'getting-started-with-the-x-twitter-api', 'X (Twitter) API', 'Step-by-step guide for posting to X/Twitter through the Post For Me API', '<h1>X (Twitter) Integration Guide</h1>
<p>This guide walks you through setting up an X (formerly Twitter) Developer App and integrating it into <strong>Post For Me</strong> so users can schedule and publish tweets directly. Feel free to contact us at <a href="mailto:postforme@daymoon.dev">postforme@daymoon.dev</a> for any additional support!</p>
<hr />
<h2>1. Create a Twitter Developer Account</h2>
<ol>
<li><p>Go to the <a href="https://developer.twitter.com/">Twitter Developer Platform</a> and sign up for a <strong>Free Developer Account</strong>.</p>
</li>
<li><p>When prompted, describe your intended use case clearly. You can use a description like:</p>
<blockquote>
<p>This app will allow users to schedule and post tweets via a unified content publishing platform we manage called Post For Me. We will only connect accounts we own or have permission to manage.</p>
</blockquote>
</li>
</ol>
<hr />
<h2>2. (Optional) Set App Details</h2>
<p>While optional, it''s recommended to complete your app profile:</p>
<ol>
<li>In the Twitter Developer Dashboard, go to your app and click <strong>Edit</strong>.</li>
<li>Add:<ul>
<li><strong>App Logo</strong></li>
<li><strong>App Description</strong></li>
<li><strong>Website URL</strong>: <code>https://www.postforme.dev</code></li>
<li><strong>Terms of Service</strong> and <strong>Privacy Policy</strong> (if planning to go public)</li>
</ul>
</li>
</ol>
<hr />
<h2>3. Configure User Authentication Settings</h2>
<ol>
<li><p>In the Twitter Developer Dashboard, go to your app, then open <strong>User authentication settings</strong> and click <strong>Set up</strong>.</p>
</li>
<li><p>Set the following:</p>
<ul>
<li><p><strong>App permissions</strong>: <code>Read and write</code></p>
</li>
<li><p><strong>Type of App</strong>: <code>Web App, Automated App, or Bot</code></p>
</li>
<li><p><strong>Callback URI / Redirect URL</strong>:</p>
<p><a href="https://app.postforme.dev/callback/">https://app.postforme.dev/callback/</a>/x/account</p>
<p>Replace <code>&lt;project_id&gt;</code> with your actual project ID in Post For Me, or copy the exact callback URL from the <strong>Configure &gt; X provider</strong> section in Post For Me.</p>
</li>
<li><p><strong>Website URL</strong>: <code>your website</code></p>
</li>
</ul>
</li>
<li><p>Click <strong>Save</strong> to apply these changes.</p>
</li>
</ol>
<hr />
<h2>4. Copy API Credentials to Post For Me</h2>
<ol>
<li>In the <strong>Keys and Tokens</strong> section of your Twitter Developer App, generate:<ul>
<li><strong>API Key</strong></li>
<li><strong>API Secret</strong></li>
</ul>
</li>
<li>In <strong>Post For Me</strong>, go to: Configure -&gt; Twitter</li>
<li>Paste the credentials into the respective fields.</li>
</ol>
<p>No need to configure the app version — Post For Me handles that automatically.</p>
<hr />
<h2>5. Connect an X Account and Test</h2>
<ol>
<li>In <strong>Post For Me</strong>, navigate to: Project -&gt; Social Media Accounts -&gt; Connect an Account</li>
<li>Choose <strong>X</strong> from the options.</li>
<li>Complete the Twitter login and authorization flow.</li>
<li>Select the X account you want to connect.</li>
</ol>
<blockquote>
<p>While your app is in <strong>Development Mode</strong>, only users added as <strong>App Roles</strong> (e.g., Owner, Admin, Developer) in the Twitter Developer Portal can connect and post.</p>
</blockquote>
<hr />
<h2>6. Move the App to Production</h2>
<p>Once you’ve verified everything is working:</p>
<ol>
<li>In the Twitter Developer Dashboard:<ul>
<li>Ensure <strong>App permissions</strong> are set to <code>Read and write</code></li>
<li>Confirm correct <strong>Redirect URL</strong> and <strong>App Type</strong></li>
</ul>
</li>
<li>Apply for <strong>Elevated Access</strong> if needed (e.g., to upload media).</li>
<li>Mark your app as ready for production use.</li>
</ol>
<hr />
<h2>Done!</h2>
<p>You''re all set! Post For Me is now fully integrated with X (Twitter). Users can connect their accounts and begin scheduling and publishing tweets directly from your platform.</p>
', 'html', NULL, false, 'published', NULL, 'cat_3idi40QLlh7LMIn3sM9mF', '2025-12-16 02:45:05.898+00', '2026-04-22 14:37:10.735956+00', '2026-04-22 14:37:10.735956+00', NULL),
	('art_CPVbbx5tkYZIk5qtzIWY2', 'getting-started-with-the-instagram-api', 'Instagram API', 'Step-by-step guide for posting to Instagram through the Post For Me API', '<h1>Facebook &amp; Instagram Integration Guide</h1>
<p>This guide walks you through setting up a Facebook App and connecting it to <strong>Post For Me</strong> so users can publish to Facebook Pages and Instagram Business accounts. Feel free to contact us at <a href="mailto:postforme@daymoon.dev">postforme@daymoon.dev</a> for any additional support!</p>
<hr />
<h2>1. Create a Facebook Developer App</h2>
<ol>
<li>Go to <a href="https://developers.facebook.com">Facebook for Developers</a>.</li>
<li>Click <strong>My Apps → Create App</strong>.</li>
<li>Select <strong>Other</strong> as the use case.</li>
<li>Choose <strong>Business</strong> as the app type.</li>
<li>Give your app a name, email, and create it.</li>
</ol>
<hr />
<h2>2. Configure Facebook Login</h2>
<ol>
<li><p>In your app dashboard, go to <strong>Add Product</strong> → <strong>Facebook Login for Business</strong>.</p>
</li>
<li><p>Under <strong>Settings → Client OAuth Settings</strong>, set:</p>
<ul>
<li><p><strong>Valid OAuth Redirect URIs</strong> to:</p>
<p><a href="https://app.postforme.dev/callback/">https://app.postforme.dev/callback/</a>/facebook/account</p>
<p><a href="https://app.postforme.dev/callback/">https://app.postforme.dev/callback/</a>/instagram/account</p>
</li>
<li><p>Replace <code>&lt;project_id&gt;</code> with your actual Post For Me project ID, or copy the full redirect URL from the <strong>Configure</strong> section of the Facebook/Instagram provider inside Post For Me.</p>
</li>
</ul>
</li>
</ol>
<hr />
<h2>3. Set App Domains and Policies</h2>
<p>In <strong>Settings → Basic</strong>:</p>
<ul>
<li>Add the <strong>App Domain</strong>: <code>app.postforme.dev</code></li>
<li>Add a <strong>Privacy Policy URL</strong>, <strong>Terms of Service URL</strong>, and <strong>App Icon</strong> if you plan to go live.</li>
<li>Save changes.</li>
</ul>
<hr />
<h2>4. Get App Credentials and Add to Post For Me</h2>
<ol>
<li><p>From <strong>Settings → Basic</strong>, copy your:</p>
<ul>
<li><strong>App ID</strong></li>
<li><strong>App Secret</strong></li>
</ul>
</li>
<li><p>In the <strong>Post For Me dashboard</strong>, go to:</p>
<ul>
<li><strong>Configure → Facebook</strong>, or</li>
<li><strong>Configure → Instagram</strong></li>
</ul>
</li>
<li><p>Paste the App ID and Secret into the appropriate fields.</p>
</li>
</ol>
<p>You do <strong>not</strong> need to set the App Version—Post For Me handles this for you.</p>
<hr />
<h2>5. Connect Accounts and Test</h2>
<h3>For <strong>Instagram Testing</strong>:</h3>
<ol>
<li>In your Facebook App Dashboard, go to <strong>Roles → Roles</strong> or <strong>Test Users</strong>.</li>
<li>Add the Instagram Business account owner as a <strong>Test User</strong>.</li>
</ol>
<h3>To Connect an Account:</h3>
<ol>
<li><p>In <strong>Post For Me</strong>, go to:</p>
<ul>
<li><strong>Project → Social Media Accounts → Connect an Account</strong></li>
</ul>
</li>
<li><p>Choose <strong>Facebook</strong> or <strong>Instagram</strong>.</p>
</li>
<li><p>Complete the Facebook login and permissions flow.</p>
</li>
<li><p>Select the Facebook Page or Instagram Business account you want to connect.</p>
</li>
</ol>
<p>While your app is in <strong>Development Mode</strong>, only test users or app roles (admin, developer, tester) can connect and post.</p>
<hr />
<h2>6. Move the App to Live Mode</h2>
<p>Once testing is successful:</p>
<ol>
<li><p>Go to <strong>App Review → Permissions and Features</strong> in the Facebook Developer Dashboard.</p>
</li>
<li><p>Request approval for the following permissions:</p>
<ul>
<li><code>pages_manage_posts</code></li>
<li><code>pages_read_engagement</code></li>
<li><code>instagram_basic</code></li>
<li><code>instagram_content_publish</code></li>
</ul>
</li>
<li><p>After approval, switch the app to <strong>Live Mode</strong>.</p>
</li>
</ol>
<hr />
<h2>Done!</h2>
<p>Your app is now fully integrated with Facebook and Instagram. Users can connect their social accounts in <strong>Post For Me</strong> and begin scheduling or publishing content.</p>
', 'html', NULL, false, 'published', NULL, 'cat_3idi40QLlh7LMIn3sM9mF', '2025-12-16 02:42:58.431+00', '2026-04-22 14:37:10.751151+00', '2026-04-22 14:37:10.751151+00', NULL),
	('art_x46tjf5efQM5Vo78I2Fl', 'getting-started-with-the-bluesky-api', 'Bluesky API', 'Step-by-step guide for posting to Bluesky through the Post For Me API', '<h1>Bluesky Integration Guide</h1>
<p>This guide walks you through setting up a Bluesky integration for <strong>Post For Me</strong>, enabling users to schedule and publish posts to their Bluesky accounts. Feel free to contact us at <a href="mailto:postforme@daymoon.dev">postforme@daymoon.dev</a> for any additional support!</p>
<hr />
<h2>Requirements</h2>
<ul>
<li>There is no setup necessary to integrate Bluesky with Post For Me. All that is needed is for users to create a Bluesky App Password.</li>
</ul>
<hr />
<h2>1. Generate a App Password</h2>
<ol>
<li>In your Bluesky account create a new app password<a href="https://bsky.app/settings/app-passwords"></a></li>
<li>Copy the newly created app password.</li>
</ol>
<h2>2. Connect your account</h2>
<ol>
<li>Go to your <strong>Post For Me project</strong>.</li>
<li>Navigate to <strong>Social Media Accounts → Connect an Account</strong>.</li>
<li>Select <strong>Bluesky</strong>.</li>
<li>Insert your Bluesky handle and the copied app password</li>
</ol>
<p>Your Bluesky account should now appear, and you can schedule or post content.</p>
<hr />
<h2>Done!</h2>
<p>Your Post For Me app is now integrated with Bluesky. Users can connect their accounts and publish content directly.</p>
', 'html', NULL, false, 'published', NULL, 'cat_3idi40QLlh7LMIn3sM9mF', '2025-12-16 02:16:05.694+00', '2026-04-22 14:37:10.780542+00', '2026-04-22 14:37:10.780542+00', NULL),
	('art_Vm7dtekZ9HCfWcsaaSfX', 'getting-started-with-the-pinterest-api', 'Pinterest API', 'Step-by-step guide for posting to Pinterest through the Post For Me API', '<h1>Pinterest Integration Guide</h1>
<p>This guide walks you through setting up a Pinterest Developer App and integrating it into <strong>Post For Me</strong> so users can schedule and publish pins directly. Feel free to contact us at <a href="mailto:postforme@daymoon.dev">postforme@daymoon.dev</a> for any additional support!</p>
<hr />
<h2>1. Create a Pinterest Developer Account</h2>
<ol>
<li>Visit the <a href="https://developers.pinterest.com">Pinterest Developer Platform</a> and sign up for a developer account.</li>
</ol>
<hr />
<h2>2. Create a New App</h2>
<ol>
<li><p>After logging in, go to the <a href="https://developers.pinterest.com/apps/">Pinterest Developer Dashboard</a> and click <strong>Connect App</strong> in the top right corner.</p>
</li>
<li><p>Fill out the required information:</p>
<ul>
<li><p><strong>App name</strong>: Choose a name for your app.</p>
</li>
<li><p><strong>Company name</strong>: Enter your company name.</p>
</li>
<li><p><strong>Website</strong>: Provide your website URL.</p>
</li>
<li><p><strong>App purpose</strong>: Provide a description of your app, for example:</p>
<blockquote>
<p>The purpose of this app is to allow us to add images and videos, called "pins", to Pinterest accounts, get data about connected accounts, and post analytics.</p>
</blockquote>
</li>
<li><p><strong>Developer purpose</strong>: Select "I am developing an app for my organization/personal use."</p>
</li>
<li><p><strong>Use cases</strong>: Choose "Pin creation &amp; scheduling" and "Reporting."</p>
</li>
<li><p><strong>Audience</strong>: Select "Pinners" and "Creators."</p>
</li>
</ul>
</li>
<li><p>Click <strong>Submit</strong>.</p>
</li>
</ol>
<blockquote>
<p>Note: It may take several days to receive a response from the Pinterest team. After you receive access, proceed to the next step.</p>
</blockquote>
<hr />
<h2>3. Copy Credentials to Post For Me</h2>
<ol>
<li>Once your application is approved, navigate to the <strong>App credentials</strong> section in the Pinterest Developer Dashboard.</li>
<li>Copy the <strong>App ID</strong> and the hidden <strong>App secret key</strong>.</li>
<li>In <strong>Post For Me</strong>, go to: Project → Configure → Pinterest</li>
<li>Paste the credentials into the respective fields.</li>
</ol>
<hr />
<h2>4. Configure Redirect URIs</h2>
<ol>
<li><p>In the Pinterest Developer Dashboard, go to the <strong>App settings</strong>.</p>
</li>
<li><p>Scroll down to the <strong>Redirect URIs</strong> field and add the following URI:<code>https://app.postforme.dev/callback/&lt;project_id&gt;/pinterest/account</code></p>
<p>Replace <code>&lt;project_id&gt;</code> with your actual project ID in Post For Me or copy the full redirect URL from the <strong>Configure</strong> section.</p>
</li>
</ol>
<hr />
<h2>5. Connect Your Account</h2>
<p>After the review, you will receive <strong>Sandbox access</strong> (Trial Tier), where your posts will only be visible to the user who created them.</p>
<p>To test:</p>
<ol>
<li>In <strong>Post For Me</strong>, navigate to: Project → Social Media Accounts → Connect an Account</li>
<li>Select <strong>Pinterest</strong>.</li>
<li>Follow the authentication flow to connect your Pinterest account.</li>
</ol>
<hr />
<h2>Upgrade to Standard Tier</h2>
<p>To make your posts public:</p>
<ol>
<li>Click the <strong>Upgrade</strong> button in the Pinterest Developer Dashboard.</li>
<li>Attach a video demonstrating your app connecting to Pinterest through Post For Me</li>
</ol>
<hr />
<h2>Done!</h2>
<p>Your integration is live! Pinterest accounts connected via Post For Me are now able to schedule and publish pins seamlessly.</p>
', 'html', NULL, false, 'published', NULL, 'cat_3idi40QLlh7LMIn3sM9mF', '2025-12-16 02:15:06.056+00', '2026-04-22 14:37:10.787978+00', '2026-04-22 14:37:10.787978+00', NULL),
	('art_jcCP5MOgKGYqehciOG8B', 'getting-started-with-the-facebook-api', 'Facebook API', 'Step-by-step guide for posting to Facebook through the Post For Me API', '<h1>Facebook &amp; Instagram Integration Guide</h1>
<p>This guide walks you through setting up a Facebook App and connecting it to <strong>Post For Me</strong> so users can publish to Facebook Pages and Instagram Business accounts. Feel free to contact us at <a href="mailto:postforme@daymoon.dev">postforme@daymoon.dev</a> for any additional support!</p>
<hr />
<h2>1. Create a Facebook Developer App</h2>
<ol>
<li>Go to <a href="https://developers.facebook.com">Facebook for Developers</a>.</li>
<li>Click <strong>My Apps → Create App</strong>.</li>
<li>Select <strong>Other</strong> as the use case.</li>
<li>Choose <strong>Business</strong> as the app type.</li>
<li>Give your app a name, email, and create it.</li>
</ol>
<hr />
<h2>2. Configure Facebook Login</h2>
<ol>
<li><p>In your app dashboard, go to <strong>Add Product</strong> → <strong>Facebook Login for Business</strong>.</p>
</li>
<li><p>Under <strong>Settings → Client OAuth Settings</strong>, set:</p>
<ul>
<li><p><strong>Valid OAuth Redirect URIs</strong> to:</p>
<p><a href="https://app.postforme.dev/callback/">https://app.postforme.dev/callback/</a>/facebook/account</p>
<p><a href="https://app.postforme.dev/callback/">https://app.postforme.dev/callback/</a>/instagram/account</p>
</li>
<li><p>Replace <code>&lt;project_id&gt;</code> with your actual Post For Me project ID, or copy the full redirect URL from the <strong>Configure</strong> section of the Facebook/Instagram provider inside Post For Me.</p>
</li>
</ul>
</li>
</ol>
<hr />
<h2>3. Set App Domains and Policies</h2>
<p>In <strong>Settings → Basic</strong>:</p>
<ul>
<li>Add the <strong>App Domain</strong>: <code>app.postforme.dev</code></li>
<li>Add a <strong>Privacy Policy URL</strong>, <strong>Terms of Service URL</strong>, and <strong>App Icon</strong> if you plan to go live.</li>
<li>Save changes.</li>
</ul>
<hr />
<h2>4. Get App Credentials and Add to Post For Me</h2>
<ol>
<li><p>From <strong>Settings → Basic</strong>, copy your:</p>
<ul>
<li><strong>App ID</strong></li>
<li><strong>App Secret</strong></li>
</ul>
</li>
<li><p>In the <strong>Post For Me dashboard</strong>, go to:</p>
<ul>
<li><strong>Configure → Facebook</strong>, or</li>
<li><strong>Configure → Instagram</strong></li>
</ul>
</li>
<li><p>Paste the App ID and Secret into the appropriate fields.</p>
</li>
</ol>
<p>You do <strong>not</strong> need to set the App Version—Post For Me handles this for you.</p>
<hr />
<h2>5. Connect Accounts and Test</h2>
<h3>For <strong>Instagram Testing</strong>:</h3>
<ol>
<li>In your Facebook App Dashboard, go to <strong>Roles → Roles</strong> or <strong>Test Users</strong>.</li>
<li>Add the Instagram Business account owner as a <strong>Test User</strong>.</li>
</ol>
<h3>To Connect an Account:</h3>
<ol>
<li><p>In <strong>Post For Me</strong>, go to:</p>
<ul>
<li><strong>Project → Social Media Accounts → Connect an Account</strong></li>
</ul>
</li>
<li><p>Choose <strong>Facebook</strong> or <strong>Instagram</strong>.</p>
</li>
<li><p>Complete the Facebook login and permissions flow.</p>
</li>
<li><p>Select the Facebook Page or Instagram Business account you want to connect.</p>
</li>
</ol>
<p>While your app is in <strong>Development Mode</strong>, only test users or app roles (admin, developer, tester) can connect and post.</p>
<hr />
<h2>6. Move the App to Live Mode</h2>
<p>Once testing is successful:</p>
<ol>
<li><p>Go to <strong>App Review → Permissions and Features</strong> in the Facebook Developer Dashboard.</p>
</li>
<li><p>Request approval for the following permissions:</p>
<ul>
<li><code>pages_manage_posts</code></li>
<li><code>pages_read_engagement</code></li>
<li><code>instagram_basic</code></li>
<li><code>instagram_content_publish</code></li>
</ul>
</li>
<li><p>After approval, switch the app to <strong>Live Mode</strong>.</p>
</li>
</ol>
<hr />
<h2>Done!</h2>
<p>Your app is now fully integrated with Facebook and Instagram. Users can connect their social accounts in <strong>Post For Me</strong> and begin scheduling or publishing content.</p>
', 'html', NULL, false, 'published', NULL, 'cat_3idi40QLlh7LMIn3sM9mF', '2025-12-16 02:11:22.906+00', '2026-04-22 14:37:10.799358+00', '2026-04-22 14:37:10.799358+00', NULL),
	('art_uPoaaVSqoSgQpE0IwKj', 'getting-started-with-the-tiktok-api', 'TikTok API', 'This guide provides step-by-step instructions for integrating TikTok with Post For Me, enabling users to schedule and publish posts to TikTok accounts. Feel free to contact us at postforme@daymoon.dev for any additional support!', '<h2>1. Create a TikTok Developer Account</h2><ol><li><p>Visit the <a target="_blank" href="https://developers.tiktok.com/">TikTok Developer Platform</a> and sign up for an account.</p></li></ol><h2>2. Create a New Application</h2><ol><li><p>After logging in, go to the <a target="_blank" href="https://developers.tiktok.com/apps/">TikTok Developer Dashboard</a> and click <strong>Create App</strong>.</p></li><li><p>Switch to <strong>Sandbox</strong></p></li><li><p>Fill in the required information:</p><ol><li><p><strong>App Name</strong>: Choose a name for your application.</p></li><li><p><strong>Company Name</strong>: Enter your company''s name.</p></li><li><p><strong>App Icon</strong>: Upload your app''s icon.</p></li><li><p><strong>Category</strong>: Select an appropriate category.</p></li><li><p><strong>Description</strong>: A brief description about your app.</p></li></ol></li><li><p>Provide the <strong>Terms of Service URL</strong> and <strong>Privacy Policy URL</strong>. TikTok will require you to verify the domain through DNS record or signature file.</p></li><li><p>Under <strong>App Products</strong>, add:</p><ol><li><p><strong>Login Kit</strong></p></li><li><p><strong>Content Posting API</strong>, Enable Direct Post</p></li><li><p>Configure the <strong>Redirect URI</strong>: <code>https://app.postforme.dev/callback/&lt;project_id&gt;/tiktok/account</code></p><ol><li><p>Replace <code>&lt;project_id&gt;</code> with your actual project ID or copy the full URL from the configure section.</p></li></ol></li></ol></li><li><p>Enable the following <strong>Scopes</strong>:</p><ol><li><p><code>user.info.basic</code></p></li><li><p><code>user.info.stats</code></p></li><li><p><code>user.info.profile</code></p></li><li><p><code>video.list</code></p></li><li><p><code>video.upload</code></p></li><li><p><code>video.publish</code> (only if Direct Post is enabled)</p></li></ol></li><li><p>Verify URL properties</p><ol><li><p>verify <code>https://app.postforme.dev/callback/</code> by URL prefix, download the file for later. Required for authentication flow through Post For Me</p></li><li><p>verify <code>https://data.postforme.dev/storage/v1/object/public/post-media/</code> by URL prefix, download the file for later. Required for Post For Me to upload media to TikTok</p></li><li><p>In <strong>Post For Me</strong> navigate to Project -&gt; Configure -&gt; TikTok -&gt; Settings Icon</p></li><li><p>Upload Verification Files using the form</p></li><li><p>Go back to TikTok App and complete the verification for each of the URLs</p></li></ol></li></ol><blockquote><p><strong><em>Note</em></strong><em>: TikTok requires a fully developed website to approve your application. With a link to the privacy policy and terms on your homepage.</em></p></blockquote><h2>4. Integrate Credentials into Post For Me</h2><ol><li><p>In the <strong>Post For Me</strong> dashboard, navigate to: Project -&gt; Configure -&gt; TikTok</p></li></ol><ol><li><p>Paste the <strong>Client ID</strong> and <strong>Client Secret</strong> into the respective fields.</p></li></ol><ol><li><p>For the <strong>Product</strong> field, select:</p></li></ol><ul><li><p><strong>Login Kit</strong> (for user authentication)</p></li></ul><ul><li><p><strong>Content Posting API</strong> (for posting content)</p></li></ul><h2>5. Connect a TikTok Account</h2><ol><li><p>In <strong>Post For Me</strong>, go to: Project -&gt; Social Media Accounts -&gt; Connect an Account</p></li></ol><ol><li><p>Select <strong>TikTok</strong>.</p></li></ol><ol><li><p>Follow the authentication flow to connect a TikTok account.</p></li></ol><h2>3. Promote to Production</h2><p>After testing the integration:</p><ol><li><p>In the TikTok Developer Dashboard, click on <strong>Production</strong>.</p></li></ol><ol><li><p>Import settings from <strong>Sandbox</strong></p></li></ol><ol><li><p>Submit for Review</p></li></ol><blockquote><p><strong><em>Note</em></strong><em>: After the App is approved there is an additional Audit needed for Direct Post.</em></p></blockquote><h2>Done!</h2><p>Your TikTok integration is now complete. You can schedule and publish posts to TikTok accounts through <strong>Post For Me</strong>.</p><p>If you need further assistance or have questions about specific features, feel free to ask!</p>', 'html', NULL, false, 'published', NULL, 'cat_3idi40QLlh7LMIn3sM9mF', '2025-10-23 18:15:54.693+00', '2026-04-22 14:37:10.80596+00', '2026-04-22 14:37:10.80596+00', NULL);


